            {
              "path": "modules/experiences/auriga/index.ts",
              "content": "/**\n * Auriga — Video Production Pipeline\n * ============================================================\n * AI-driven video production from brief to final export.\n * Manages sessions through an 8-stage pipeline:\n *   brief → ingest → analyze → structure → music → rough_cut → refine → export\n *\n * Each session tracks assets (raw footage, references, title cards,\n * music, narration, cuts, finals) and visual DNA analysis per asset.\n *\n * ffmpeg/ffprobe wrappers handle all media operations.\n * ============================================================\n */\n\nimport { createRequire } from \"node:module\";\nimport { randomUUID } from \"node:crypto\";\nimport { execFile as execFileCb } from \"node:child_process\";\nimport { promisify } from \"node:util\";\nimport { access, constants } from \"node:fs/promises\";\nimport { resolve } from \"node:path\";\nimport type { SquidleyModule, ModuleContext, HealthReport } from \"@squidley/core/sdk\";\n\nimport { stateDir } from \"@squidley/core/paths\";\n\nconst require = createRequire(import.meta.url);\nconst execFile = promisify(execFileCb);\n\nconst STATE_DIR = stateDir();\nconst DB_PATH = resolve(STATE_DIR, \"auriga.db\");\n\n// ── Pipeline Stages ──────────────────────────────────────────────────────────\n\nexport const PIPELINE_STAGES = [\n  \"brief\",\n  \"ingest\",\n  \"analyze\",\n  \"structure\",\n  \"music\",\n  \"rough_cut\",\n  \"refine\",\n  \"export\",\n] as const;\n\nexport type PipelineStage = (typeof PIPELINE_STAGES)[number];\n\nexport const STAGE_DESCRIPTIONS: Record<PipelineStage, string> = {\n  brief: \"Understanding what you want to create\",\n  ingest: \"Bringing in your footage and references\",\n  analyze: \"Studying each clip — content, quality, best moments\",\n  structure: \"Building the story arc and shot sequence\",\n  music: \"Creating or selecting the soundtrack\",\n  rough_cut: \"Assembling the first cut with transitions\",\n  refine: \"Polish — color, pacing, titles, lower-thirds\",\n  export: \"Final render to MP4\",\n};\n\n// ── Types ─────────────────────────────────────────────────────────────────────\n\nexport type SessionMode = \"video\" | \"demo\" | \"music\";\nexport type SessionStatus = \"active\" | \"paused\" | \"complete\" | \"archived\";\nexport type StageStatus = \"pending\" | \"running\" | \"complete\" | \"approved\" | \"redirected\";\nexport type AssetType = \"raw\" | \"reference\" | \"title_card\" | \"music\" | \"narration\" | \"cut\" | \"final\";\n\nexport interface AurigaSession {\n  id: string;\n  name: string;\n  mode: SessionMode;\n  status: SessionStatus;\n  current_stage: string;\n  brief: string;\n  created_at: string;\n  updated_at: string;\n}\n\nexport interface AurigaStage {\n  id: string;\n  session_id: string;\n  stage: PipelineStage;\n  status: StageStatus;\n  output: string | null;\n  started_at: string | null;\n  completed_at: string | null;\n  approved_at: string | null;\n  approval_note: string | null;\n}\n\nexport interface AurigaAsset {\n  id: string;\n  session_id: string;\n  type: AssetType;\n  filename: string;\n  mime_type: string;\n  archivum_id: string | null;\n  dna_id: string | null;\n  metadata: string | null;\n  created_at: string;\n}\n\nexport interface AurigaDna {\n  id: string;\n  asset_id: string;\n  color_palette: string[];\n  dominant_shapes: string;\n  style_tags: string[];\n  content_hash: string;\n  analysis_model: string;\n  created_at: string;\n}\n\nexport interface ProbeResult {\n  duration: number;\n  width: number;\n  height: number;\n  fps: number;\n  codec_video: string;\n  codec_audio: string;\n  format: string;\n  bitrate: number;\n}\n\nexport interface EncodeOptions {\n  crf?: number;\n  preset?: string;\n  audioBitrate?: string;\n  videoBitrate?: string;\n  resolution?: string;\n  fps?: number;\n}\n\n// ── Database ──────────────────────────────────────────────────────────────────\n\nexport class AurigaDB {\n  private db: { pragma: (sql: string) => unknown; prepare: (sql: string) => any; exec: (sql: string) => unknown; transaction: <T extends (...args: any[]) => any>(fn: T) => T; close: () => void };\n\n  constructor(dbPath: string = DB_PATH) {\n    // eslint-disable-next-line @typescript-eslint/no-var-requires\n    const BetterSqlite3 = require(\"better-sqlite3\") as any;\n    const DatabaseCtor = BetterSqlite3.default ?? BetterSqlite3;\n    this.db = new DatabaseCtor(dbPath) as typeof this.db;\n    this.db.pragma(\"journal_mode = WAL\");\n    this.db.pragma(\"foreign_keys = ON\");\n    this.migrate();\n  }\n\n  private migrate(): void {\n    this.db.exec(`\n      CREATE TABLE IF NOT EXISTS auriga_sessions (\n        id            TEXT PRIMARY KEY,\n        name          TEXT NOT NULL,\n        mode          TEXT NOT NULL CHECK (mode IN ('video', 'demo', 'music')),\n        status        TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'paused', 'complete', 'archived')),\n        current_stage TEXT NOT NULL DEFAULT 'brief',\n        brief         TEXT NOT NULL DEFAULT '',\n        created_at    TEXT NOT NULL,\n        updated_at    TEXT NOT NULL\n      );\n\n      CREATE TABLE IF NOT EXISTS auriga_stages (\n        id            TEXT PRIMARY KEY,\n        session_id    TEXT NOT NULL REFERENCES auriga_sessions(id) ON DELETE CASCADE,\n        stage         TEXT NOT NULL CHECK (stage IN ('brief', 'ingest', 'analyze', 'structure', 'music', 'rough_cut', 'refine', 'export')),\n        status        TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'running', 'complete', 'approved', 'redirected')),\n        output        TEXT,\n        started_at    TEXT,\n        completed_at  TEXT,\n        approved_at   TEXT,\n        approval_note TEXT\n      );\n\n      CREATE TABLE IF NOT EXISTS auriga_assets (\n        id           TEXT PRIMARY KEY,\n        session_id   TEXT NOT NULL REFERENCES auriga_sessions(id) ON DELETE CASCADE,\n        type         TEXT NOT NULL CHECK (type IN ('raw', 'reference', 'title_card', 'music', 'narration', 'cut', 'final')),\n        filename     TEXT NOT NULL,\n        mime_type    TEXT NOT NULL,\n        archivum_id  TEXT,\n        dna_id       TEXT,\n        metadata     TEXT,\n        created_at   TEXT NOT NULL\n      );\n\n      CREATE TABLE IF NOT EXISTS auriga_dna (\n        id              TEXT PRIMARY KEY,\n        asset_id        TEXT NOT NULL REFERENCES auriga_assets(id) ON DELETE CASCADE,\n        color_palette   TEXT NOT NULL DEFAULT '[]',\n        dominant_shapes TEXT NOT NULL DEFAULT '',\n        style_tags      TEXT NOT NULL DEFAULT '[]',\n        content_hash    TEXT NOT NULL DEFAULT '',\n        analysis_model  TEXT NOT NULL DEFAULT '',\n        created_at      TEXT NOT NULL\n      );\n\n      CREATE INDEX IF NOT EXISTS idx_stages_session ON auriga_stages(session_id);\n      CREATE INDEX IF NOT EXISTS idx_assets_session ON auriga_assets(session_id);\n      CREATE INDEX IF NOT EXISTS idx_dna_asset ON auriga_dna(asset_id);\n    `);\n\n    // Migration: add 'music' to mode CHECK constraint (SQLite requires table recreation)\n    try {\n      const tableInfo = this.db.prepare(\"SELECT sql FROM sqlite_master WHERE type='table' AND name='auriga_sessions'\").get() as { sql: string } | undefined;\n      if (tableInfo?.sql && !tableInfo.sql.includes(\"'music'\")) {\n        this.db.exec(`\n          CREATE TABLE IF NOT EXISTS auriga_sessions_new (\n            id            TEXT PRIMARY KEY,\n            name          TEXT NOT NULL,\n            mode          TEXT NOT NULL CHECK (mode IN ('video', 'demo', 'music')),\n            status        TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'paused', 'complete', 'archived')),\n            current_stage TEXT NOT NULL DEFAULT 'brief',\n            brief         TEXT NOT NULL DEFAULT '',\n            created_at    TEXT NOT NULL,\n            updated_at    TEXT NOT NULL\n          );\n          INSERT INTO auriga_sessions_new SELECT * FROM auriga_sessions;\n          DROP TABLE auriga_sessions;\n          ALTER TABLE auriga_sessions_new RENAME TO auriga_sessions;\n        `);\n      }\n    } catch { /* migration already applied or no data */ }\n  }\n\n  // ── Sessions ─────────────────────────────────────────────────────────────\n\n  createSession(name: string, mode: SessionMode, brief: string): AurigaSession {\n    const now = new Date().toISOString();\n    const session: AurigaSession = {\n      id: randomUUID(),\n      name,\n      mode,\n      status: \"active\",\n      current_stage: \"brief\",\n      brief,\n      created_at: now,\n      updated_at: now,\n    };\n\n    this.db.prepare(`\n      INSERT INTO auriga_sessions (id, name, mode, status, current_stage, brief, created_at, updated_at)\n      VALUES (@id, @name, @mode, @status, @current_stage, @brief, @created_at, @updated_at)\n    `).run(session);\n\n    // Seed all pipeline stages\n    const stageInsert = this.db.prepare(`\n      INSERT INTO auriga_stages (id, session_id, stage, status)\n      VALUES (?, ?, ?, 'pending')\n    `);\n    const seedStages = this.db.transaction(() => {\n      for (const stage of PIPELINE_STAGES) {\n        stageInsert.run(randomUUID(), session.id, stage);\n      }\n    });\n    seedStages();\n\n    return session;\n  }\n\n  getSession(id: string): (AurigaSession & { stages: AurigaStage[]; assets: AurigaAsset[] }) | null {\n    const session = this.db.prepare(\"SELECT * FROM auriga_sessions WHERE id = ?\").get(id) as AurigaSession | undefined;\n    if (!session) return null;\n\n    const stages = this.db.prepare(\"SELECT * FROM auriga_stages WHERE session_id = ? ORDER BY CASE stage WHEN 'brief' THEN 0 WHEN 'ingest' THEN 1 WHEN 'analyze' THEN 2 WHEN 'structure' THEN 3 WHEN 'music' THEN 4 WHEN 'rough_cut' THEN 5 WHEN 'refine' THEN 6 WHEN 'export' THEN 7 END\").all(id) as AurigaStage[];\n    const assets = this.db.prepare(\"SELECT * FROM auriga_assets WHERE session_id = ? ORDER BY created_at\").all(id) as AurigaAsset[];\n\n    return { ...session, stages, assets };\n  }\n\n  listSessions(): AurigaSession[] {\n    return this.db.prepare(\"SELECT * FROM auriga_sessions ORDER BY updated_at DESC\").all() as AurigaSession[];\n  }\n\n  updateSession(id: string, patch: Partial<Pick<AurigaSession, \"name\" | \"mode\" | \"status\" | \"current_stage\" | \"brief\">>): boolean {\n    const fields: string[] = [];\n    const values: unknown[] = [];\n\n    for (const [key, value] of Object.entries(patch)) {\n      if (value !== undefined && [\"name\", \"mode\", \"status\", \"current_stage\", \"brief\"].includes(key)) {\n        fields.push(`${key} = ?`);\n        values.push(value);\n      }\n    }\n\n    if (fields.length === 0) return false;\n\n    fields.push(\"updated_at = ?\");\n    values.push(new Date().toISOString());\n    values.push(id);\n\n    const result = this.db.prepare(`UPDATE auriga_sessions SET ${fields.join(\", \")} WHERE id = ?`).run(...values);\n    return result.changes > 0;\n  }\n\n  deleteSession(id: string): boolean {\n    // CASCADE handles stages, assets. DNA cascades from assets.\n    const result = this.db.prepare(\"DELETE FROM auriga_sessions WHERE id = ?\").run(id);\n    return result.changes > 0;\n  }\n\n  // ── Stages ───────────────────────────────────────────────────────────────\n\n  addStage(sessionId: string, stage: PipelineStage): AurigaStage {\n    const row: AurigaStage = {\n      id: randomUUID(),\n      session_id: sessionId,\n      stage,\n      status: \"pending\",\n      output: null,\n      started_at: null,\n      completed_at: null,\n      approved_at: null,\n      approval_note: null,\n    };\n\n    this.db.prepare(`\n      INSERT INTO auriga_stages (id, session_id, stage, status, output, started_at, completed_at, approved_at, approval_note)\n      VALUES (@id, @session_id, @stage, @status, @output, @started_at, @completed_at, @approved_at, @approval_note)\n    `).run(row);\n\n    return row;\n  }\n\n  updateStage(stageId: string, patch: Partial<Pick<AurigaStage, \"status\" | \"output\" | \"approved_at\" | \"approval_note\">>): boolean {\n    const fields: string[] = [];\n    const values: unknown[] = [];\n\n    for (const [key, value] of Object.entries(patch)) {\n      if (value !== undefined && [\"status\", \"output\", \"approved_at\", \"approval_note\"].includes(key)) {\n        fields.push(`${key} = ?`);\n        values.push(value);\n      }\n    }\n\n    if (fields.length === 0) return false;\n\n    // Auto-set timestamps based on status transitions\n    if (patch.status === \"running\" && !patch.approved_at) {\n      fields.push(\"started_at = ?\");\n      values.push(new Date().toISOString());\n    }\n    if (patch.status === \"complete\" || patch.status === \"approved\") {\n      fields.push(\"completed_at = ?\");\n      values.push(new Date().toISOString());\n    }\n    if (patch.status === \"approved\") {\n      fields.push(\"approved_at = ?\");\n      values.push(new Date().toISOString());\n    }\n\n    values.push(stageId);\n    const result = this.db.prepare(`UPDATE auriga_stages SET ${fields.join(\", \")} WHERE id = ?`).run(...values);\n    return result.changes > 0;\n  }\n\n  getStages(sessionId: string): AurigaStage[] {\n    return this.db.prepare(\n      \"SELECT * FROM auriga_stages WHERE session_id = ? ORDER BY CASE stage WHEN 'brief' THEN 0 WHEN 'ingest' THEN 1 WHEN 'analyze' THEN 2 WHEN 'structure' THEN 3 WHEN 'music' THEN 4 WHEN 'rough_cut' THEN 5 WHEN 'refine' THEN 6 WHEN 'export' THEN 7 END\"\n    ).all(sessionId) as AurigaStage[];\n  }\n\n  // ── Assets ───────────────────────────────────────────────────────────────\n\n  addAsset(\n    sessionId: string,\n    type: AssetType,\n    filename: string,\n    mimeType: string,\n    archivumId: string | null = null,\n    metadata: Record<string, unknown> | null = null,\n  ): AurigaAsset {\n    const asset: AurigaAsset = {\n      id: randomUUID(),\n      session_id: sessionId,\n      type,\n      filename,\n      mime_type: mimeType,\n      archivum_id: archivumId,\n      dna_id: null,\n      metadata: metadata ? JSON.stringify(metadata) : null,\n      created_at: new Date().toISOString(),\n    };\n\n    this.db.prepare(`\n      INSERT INTO auriga_assets (id, session_id, type, filename, mime_type, archivum_id, dna_id, metadata, created_at)\n      VALUES (@id, @session_id, @type, @filename, @mime_type, @archivum_id, @dna_id, @metadata, @created_at)\n    `).run(asset);\n\n    return asset;\n  }\n\n  getAssets(sessionId: string): AurigaAsset[] {\n    return this.db.prepare(\"SELECT * FROM auriga_assets WHERE session_id = ? ORDER BY created_at\").all(sessionId) as AurigaAsset[];\n  }\n\n  // ── DNA ──────────────────────────────────────────────────────────────────\n\n  saveDna(assetId: string, dna: Omit<AurigaDna, \"id\" | \"asset_id\" | \"created_at\">): AurigaDna {\n    const row: AurigaDna = {\n      id: randomUUID(),\n      asset_id: assetId,\n      color_palette: dna.color_palette,\n      dominant_shapes: dna.dominant_shapes,\n      style_tags: dna.style_tags,\n      content_hash: dna.content_hash,\n      analysis_model: dna.analysis_model,\n      created_at: new Date().toISOString(),\n    };\n\n    this.db.prepare(`\n      INSERT INTO auriga_dna (id, asset_id, color_palette, dominant_shapes, style_tags, content_hash, analysis_model, created_at)\n      VALUES (?, ?, ?, ?, ?, ?, ?, ?)\n    `).run(\n      row.id,\n      row.asset_id,\n      JSON.stringify(row.color_palette),\n      row.dominant_shapes,\n      JSON.stringify(row.style_tags),\n      row.content_hash,\n      row.analysis_model,\n      row.created_at,\n    );\n\n    // Link DNA back to asset\n    this.db.prepare(\"UPDATE auriga_assets SET dna_id = ? WHERE id = ?\").run(row.id, assetId);\n\n    return row;\n  }\n\n  getDna(assetId: string): AurigaDna | null {\n    const row = this.db.prepare(\"SELECT * FROM auriga_dna WHERE asset_id = ?\").get(assetId) as\n      | { id: string; asset_id: string; color_palette: string; dominant_shapes: string; style_tags: string; content_hash: string; analysis_model: string; created_at: string }\n      | undefined;\n    if (!row) return null;\n\n    return {\n      ...row,\n      color_palette: JSON.parse(row.color_palette) as string[],\n      style_tags: JSON.parse(row.style_tags) as string[],\n    };\n  }\n\n  // ── Cleanup ──────────────────────────────────────────────────────────────\n\n  close(): void {\n    this.db.close();\n  }\n}\n\n// ── ffmpeg Helpers ─────────────────────────────────────────────────────────────\n\nasync function findBinary(name: string): Promise<string> {\n  try {\n    const { stdout } = await execFile(\"which\", [name]);\n    return stdout.trim();\n  } catch {\n    throw new Error(`${name} not found in PATH`);\n  }\n}\n\nexport async function probe(filePath: string): Promise<ProbeResult> {\n  const bin = await findBinary(\"ffprobe\");\n  const { stdout } = await execFile(bin, [\n    \"-v\", \"quiet\",\n    \"-print_format\", \"json\",\n    \"-show_format\",\n    \"-show_streams\",\n    filePath,\n  ], { timeout: 30_000 });\n\n  const data = JSON.parse(stdout) as {\n    format?: { duration?: string; bit_rate?: string; format_name?: string };\n    streams?: Array<{\n      codec_type?: string;\n      codec_name?: string;\n      width?: number;\n      height?: number;\n      r_frame_rate?: string;\n    }>;\n  };\n\n  const videoStream = data.streams?.find(s => s.codec_type === \"video\");\n  const audioStream = data.streams?.find(s => s.codec_type === \"audio\");\n\n  let fps = 0;\n  if (videoStream?.r_frame_rate) {\n    const parts = videoStream.r_frame_rate.split(\"/\");\n    if (parts.length === 2) {\n      const num = parseInt(parts[0]!, 10);\n      const den = parseInt(parts[1]!, 10);\n      if (den > 0) fps = Math.round((num / den) * 100) / 100;\n    }\n  }\n\n  return {\n    duration: parseFloat(data.format?.duration ?? \"0\"),\n    width: videoStream?.width ?? 0,\n    height: videoStream?.height ?? 0,\n    fps,\n    codec_video: videoStream?.codec_name ?? \"unknown\",\n    codec_audio: audioStream?.codec_name ?? \"none\",\n    format: data.format?.format_name ?? \"unknown\",\n    bitrate: parseInt(data.format?.bit_rate ?? \"0\", 10),\n  };\n}\n\nexport async function cut(input: string, start: number, duration: number, output: string): Promise<string> {\n  const bin = await findBinary(\"ffmpeg\");\n  await execFile(bin, [\n    \"-y\", \"-ss\", String(start), \"-t\", String(duration),\n    \"-i\", input,\n    \"-c\", \"copy\",\n    \"-avoid_negative_ts\", \"make_zero\",\n    output,\n  ], { timeout: 120_000 });\n  return output;\n}\n\nexport async function concat(inputs: string[], output: string): Promise<string> {\n  const bin = await findBinary(\"ffmpeg\");\n  // Build concat filter with re-encode for safe concatenation\n  const filterParts: string[] = [];\n  const args: string[] = [\"-y\"];\n\n  for (const input of inputs) {\n    args.push(\"-i\", input);\n  }\n\n  for (let i = 0; i < inputs.length; i++) {\n    filterParts.push(`[${i}:v:0][${i}:a:0]`);\n  }\n\n  args.push(\n    \"-filter_complex\",\n    `${filterParts.join(\"\")}concat=n=${inputs.length}:v=1:a=1[outv][outa]`,\n    \"-map\", \"[outv]\", \"-map\", \"[outa]\",\n    \"-c:v\", \"libx264\", \"-preset\", \"medium\", \"-crf\", \"18\",\n    \"-c:a\", \"aac\", \"-b:a\", \"192k\",\n    output,\n  );\n\n  await execFile(bin, args, { timeout: 600_000 });\n  return output;\n}\n\nexport async function overlay(base: string, overlayPath: string, position: string, output: string): Promise<string> {\n  const bin = await findBinary(\"ffmpeg\");\n\n  // Parse position: \"top-left\", \"top-right\", \"bottom-left\", \"bottom-right\", \"center\", or \"x:y\"\n  let overlayPos: string;\n  switch (position) {\n    case \"top-left\":      overlayPos = \"10:10\"; break;\n    case \"top-right\":     overlayPos = \"main_w-overlay_w-10:10\"; break;\n    case \"bottom-left\":   overlayPos = \"10:main_h-overlay_h-10\"; break;\n    case \"bottom-right\":  overlayPos = \"main_w-overlay_w-10:main_h-overlay_h-10\"; break;\n    case \"center\":        overlayPos = \"(main_w-overlay_w)/2:(main_h-overlay_h)/2\"; break;\n    default:              overlayPos = position; break;\n  }\n\n  await execFile(bin, [\n    \"-y\",\n    \"-i\", base,\n    \"-i\", overlayPath,\n    \"-filter_complex\", `[0:v][1:v]overlay=${overlayPos}[outv]`,\n    \"-map\", \"[outv]\", \"-map\", \"0:a?\",\n    \"-c:v\", \"libx264\", \"-preset\", \"medium\", \"-crf\", \"18\",\n    \"-c:a\", \"copy\",\n    output,\n  ], { timeout: 300_000 });\n  return output;\n}\n\nexport async function addTitleCard(\n  text: string,\n  duration: number,\n  resolution: string,\n  output: string,\n): Promise<string> {\n  const bin = await findBinary(\"ffmpeg\");\n  const [width, height] = resolution.split(\"x\").map(Number);\n\n  const fontSize = Math.round((width ?? 1920) / 30);\n  const escapedText = text.replace(/'/g, \"'\\\\''\").replace(/:/g, \"\\\\:\");\n\n  await execFile(bin, [\n    \"-y\",\n    \"-f\", \"lavfi\",\n    \"-i\", `color=c=black:s=${width ?? 1920}x${height ?? 1080}:d=${duration}:r=30`,\n    \"-f\", \"lavfi\",\n    \"-i\", `anullsrc=r=48000:cl=stereo`,\n    \"-t\", String(duration),\n    \"-vf\", `drawtext=text='${escapedText}':fontcolor=white:fontsize=${fontSize}:x=(w-text_w)/2:y=(h-text_h)/2:font=sans`,\n    \"-c:v\", \"libx264\", \"-preset\", \"medium\", \"-crf\", \"18\",\n    \"-c:a\", \"aac\", \"-b:a\", \"128k\",\n    \"-shortest\",\n    output,\n  ], { timeout: 60_000 });\n  return output;\n}\n\nexport async function addLowerThird(\n  input: string,\n  text: string,\n  startTime: number,\n  duration: number,\n  output: string,\n): Promise<string> {\n  const bin = await findBinary(\"ffmpeg\");\n  const escapedText = text.replace(/'/g, \"'\\\\''\").replace(/:/g, \"\\\\:\");\n\n  await execFile(bin, [\n    \"-y\",\n    \"-i\", input,\n    \"-vf\", [\n      `drawbox=x=0:y=ih-ih/6:w=iw:h=ih/6:color=black@0.6:t=fill:enable='between(t,${startTime},${startTime + duration})'`,\n      `drawtext=text='${escapedText}':fontcolor=white:fontsize=36:x=40:y=h-h/6+20:font=sans:enable='between(t,${startTime},${startTime + duration})'`,\n    ].join(\",\"),\n    \"-c:v\", \"libx264\", \"-preset\", \"medium\", \"-crf\", \"18\",\n    \"-c:a\", \"copy\",\n    output,\n  ], { timeout: 300_000 });\n  return output;\n}\n\nexport async function addWatermark(input: string, watermarkPath: string, output: string): Promise<string> {\n  return overlay(input, watermarkPath, \"bottom-right\", output);\n}\n\nexport async function encode(input: string, output: string, options: EncodeOptions = {}): Promise<string> {\n  const bin = await findBinary(\"ffmpeg\");\n  const {\n    crf = 20,\n    preset = \"medium\",\n    audioBitrate = \"192k\",\n    videoBitrate,\n    resolution,\n    fps,\n  } = options;\n\n  const args: string[] = [\"-y\", \"-i\", input];\n\n  // Video filters\n  const vf: string[] = [];\n  if (resolution) vf.push(`scale=${resolution.replace(\"x\", \":\")}`);\n  if (fps) vf.push(`fps=${fps}`);\n  if (vf.length > 0) args.push(\"-vf\", vf.join(\",\"));\n\n  // Video codec\n  args.push(\"-c:v\", \"libx264\", \"-preset\", preset);\n  if (videoBitrate) {\n    args.push(\"-b:v\", videoBitrate);\n  } else {\n    args.push(\"-crf\", String(crf));\n  }\n\n  // Audio codec\n  args.push(\"-c:a\", \"aac\", \"-b:a\", audioBitrate);\n\n  // Container\n  args.push(\"-movflags\", \"+faststart\", output);\n\n  await execFile(bin, args, { timeout: 600_000 });\n  return output;\n}\n\n// ── ffmpeg availability check ─────────────────────────────────────────────────\n\nasync function checkBinary(name: string): Promise<{ available: boolean; version: string }> {\n  try {\n    const { stdout } = await execFile(name, [\"-version\"], { timeout: 5_000 });\n    const firstLine = stdout.split(\"\\n\")[0] ?? \"\";\n    const versionMatch = firstLine.match(/version\\s+([\\d.]+)/);\n    return { available: true, version: versionMatch?.[1] ?? \"unknown\" };\n  } catch {\n    return { available: false, version: \"\" };\n  }\n}\n\n// ── Module singleton ──────────────────────────────────────────────────────────\n\nlet db: AurigaDB | null = null;\n\nfunction getDB(): AurigaDB {\n  if (!db) db = new AurigaDB(DB_PATH);\n  return db;\n}\n\n// ── Module ────────────────────────────────────────────────────────────────────\n\nexport const AurigaModule: SquidleyModule = {\n  manifest: {\n    id: \"squidley.experience.auriga\",\n    name: \"Auriga\",\n    version: \"2.0.0\",\n    apiVersion: \"2.0.0\",\n    description: \"AI-driven video production pipeline — brief to final export\",\n    category: \"experience\",\n  },\n\n  dependencies: {\n    required: [\"squidley.system.provider-manager\"],\n    optional: [\"squidley.integration.archivum\", \"squidley.integration.comfyui\"],\n    versionRequirements: {},\n  },\n  config: {\n    schema: {\n      stateDir: { type: \"string\", description: \"State directory for auriga.db\", required: false },\n    },\n    required: [],\n    defaults: {},\n    secrets: [],\n  },\n  capabilities: [\"fs.read\", \"fs.write\", \"shell.exec\", \"network.outbound\", \"receipts.write\"],\n  events: {\n    subscribes: [],\n    emits: [\"auriga.session.created\", \"auriga.stage.complete\", \"auriga.export.done\"],\n  },\n\n  async init(ctx: ModuleContext) {\n    const instance = getDB();\n\n    ctx.registerService({\n      serviceId: \"auriga\",\n      interfaceName: \"AurigaService\",\n      implementation: {\n        // DB methods\n        createSession: (name: string, mode: SessionMode, brief: string) => instance.createSession(name, mode, brief),\n        getSession: (id: string) => instance.getSession(id),\n        listSessions: () => instance.listSessions(),\n        updateSession: (id: string, patch: Partial<Pick<AurigaSession, \"name\" | \"mode\" | \"status\" | \"current_stage\" | \"brief\">>) => instance.updateSession(id, patch),\n        deleteSession: (id: string) => instance.deleteSession(id),\n        addStage: (sessionId: string, stage: PipelineStage) => instance.addStage(sessionId, stage),\n        updateStage: (stageId: string, patch: Partial<Pick<AurigaStage, \"status\" | \"output\" | \"approved_at\" | \"approval_note\">>) => instance.updateStage(stageId, patch),\n        getStages: (sessionId: string) => instance.getStages(sessionId),\n        addAsset: (sessionId: string, type: AssetType, filename: string, mimeType: string, archivumId: string | null, metadata: Record<string, unknown> | null) => instance.addAsset(sessionId, type, filename, mimeType, archivumId, metadata),\n        getAssets: (sessionId: string) => instance.getAssets(sessionId),\n        saveDna: (assetId: string, dna: Omit<AurigaDna, \"id\" | \"asset_id\" | \"created_at\">) => instance.saveDna(assetId, dna),\n        getDna: (assetId: string) => instance.getDna(assetId),\n\n        // ffmpeg helpers\n        probe,\n        cut,\n        concat,\n        overlay,\n        addTitleCard,\n        addLowerThird,\n        addWatermark,\n        encode,\n\n        // Pipeline metadata\n        stages: PIPELINE_STAGES,\n        stageDescriptions: STAGE_DESCRIPTIONS,\n      },\n    });\n\n    ctx.log.info(`auriga ready — db=${DB_PATH} pipeline=${PIPELINE_STAGES.length} stages`);\n  },\n\n  async start() {},\n\n  async stop() {\n    if (db) {\n      db.close();\n      db = null;\n    }\n  },\n\n  async healthCheck(): Promise<HealthReport> {\n    const checks: Record<string, boolean> = {};\n\n    // Check ffmpeg\n    const ffmpegStatus = await checkBinary(\"ffmpeg\");\n    checks[\"ffmpeg\"] = ffmpegStatus.available;\n\n    // Check ffprobe\n    const ffprobeStatus = await checkBinary(\"ffprobe\");\n    checks[\"ffprobe\"] = ffprobeStatus.available;\n\n    // Check database\n    let dbOk = false;\n    let sessionCount = 0;\n    try {\n      const instance = getDB();\n      const row = instance[\"db\"].prepare(\"SELECT COUNT(*) as cnt FROM auriga_sessions\").get() as { cnt: number };\n      sessionCount = row.cnt;\n      dbOk = true;\n    } catch {\n      dbOk = false;\n    }\n    checks[\"database\"] = dbOk;\n\n    const allGood = checks[\"ffmpeg\"] && checks[\"ffprobe\"] && checks[\"database\"];\n    const parts: string[] = [];\n\n    if (ffmpegStatus.available) {\n      parts.push(`ffmpeg ${ffmpegStatus.version}`);\n    } else {\n      parts.push(\"ffmpeg missing\");\n    }\n\n    if (ffprobeStatus.available) {\n      parts.push(`ffprobe ${ffprobeStatus.version}`);\n    } else {\n      parts.push(\"ffprobe missing\");\n    }\n\n    if (dbOk) {\n      parts.push(`${sessionCount} session${sessionCount === 1 ? \"\" : \"s\"}`);\n    } else {\n      parts.push(\"db error\");\n    }\n\n    if (allGood) {\n      return { status: \"healthy\", message: parts.join(\" · \"), checks };\n    }\n\n    if (dbOk) {\n      // ffmpeg missing but DB works — degraded but functional for session management\n      return { status: \"degraded\", message: parts.join(\" · \"), checks, expectedDegraded: !ffmpegStatus.available };\n    }\n\n    return { status: \"failed\", message: parts.join(\" · \"), checks };\n  },\n};\n",
