              "path": "modules/experiences/cursus/index.ts",
              "content": "/**\n * Cursus V2 — Career Change Command Center\n * ============================================================\n * The reason Squidley was built. Career transformation engine\n * with Dux counselor AI, 7-agent fleet, resume builder, Gmail\n * integration, and job pipeline management.\n *\n * Tables (new — existing cursus_* tables preserved):\n *   cursus_campaigns    — active job search campaigns\n *   cursus_applications — the job pipeline\n *   cursus_resumes      — resume versions (base + tailored)\n *   cursus_outreach     — staged/approved/sent communications\n *   cursus_dux_sessions — Dux interview conversation history\n *\n * Stealth doctrine: nothing sends without explicit approval.\n * ============================================================\n */\n\nimport { createRequire } from \"node:module\";\nimport { randomUUID } from \"node:crypto\";\nimport { mkdirSync } from \"node:fs\";\nimport { join } from \"node:path\";\nimport type { SquidleyModule, ModuleContext, HealthReport } from \"@squidley/core/sdk\";\n\nconst require = createRequire(import.meta.url);\nconst STATE_DIR = process.env[\"SQUIDLEY_STATE_DIR\"] ?? \"/mnt/ai/squidley-v2/state\";\nconst DB_PATH = join(STATE_DIR, \"cursus.db\");\n\n// ── Types ─────────────────────────────────────────────────────────────────────\n\nexport type CampaignPhase = \"research\" | \"applying\" | \"interviewing\" | \"negotiating\" | \"closed\";\nexport type AppStatus = \"found\" | \"qualified\" | \"applied\" | \"responded\" | \"interviewing\" | \"closed\";\nexport type OutreachType = \"email\" | \"cover_letter\" | \"recruiter\";\nexport type OutreachStatus = \"staged\" | \"approved\" | \"sent\" | \"replied\";\nexport type DuxSessionType = \"interview\" | \"checkin\" | \"role_assessment\" | \"discovery\";\n\nexport interface Campaign {\n  id: string; name: string; target_role: string; phase: CampaignPhase;\n  milestones: string; active: boolean; created_at: string;\n}\n\nexport interface Application {\n  id: string; campaign_id: string; company: string; role: string;\n  url: string | null; salary_range: string | null; match_score: number | null;\n  status: AppStatus; notes: string | null; applied_at: string | null;\n  follow_up_at: string | null; created_at: string;\n}\n\nexport interface Resume {\n  id: string; profile_version: number | null; base_resume: string;\n  tailored_for: string | null; created_at: string;\n}\n\nexport interface Outreach {\n  id: string; application_id: string | null; type: OutreachType;\n  subject: string; body: string; status: OutreachStatus;\n  created_at: string; sent_at: string | null; gmail_thread_id: string | null;\n}\n\nexport interface DuxSession {\n  id: string; session_type: DuxSessionType; messages: string;\n  profile_version_generated: number | null; created_at: string;\n}\n\nexport interface DashboardStats {\n  activeCampaign: Campaign | null;\n  applicationCounts: Record<AppStatus, number>;\n  totalApplications: number;\n  pendingOutreach: number;\n  approvedOutreach: number;\n  sentOutreach: number;\n  repliedOutreach: number;\n  lastDuxSession: string | null;\n  recentActivity: Array<{ type: string; detail: string; timestamp: string }>;\n}\n\n// ── Database ──────────────────────────────────────────────────────────────────\n\nexport class CursusV2DB {\n  // eslint-disable-next-line @typescript-eslint/no-explicit-any\n  private db: any;\n\n  constructor(dbPath: string = DB_PATH) {\n    mkdirSync(join(dbPath, \"..\"), { recursive: true });\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    const BetterSqlite3 = require(\"better-sqlite3\") as any;\n    const DatabaseCtor = BetterSqlite3.default ?? BetterSqlite3;\n    this.db = new DatabaseCtor(dbPath);\n    this.db.pragma(\"journal_mode = WAL\");\n    this.migrate();\n  }\n\n  private migrate(): void {\n    // ── Add stealth cover + V2 columns to existing profile (safe — ALTER ignores if exists) ──\n    const profileCols = [\n      \"ALTER TABLE cursus_profile ADD COLUMN cover_employer TEXT DEFAULT 'Confidential — Plant Tissue Culture Laboratory'\",\n      \"ALTER TABLE cursus_profile ADD COLUMN cover_role TEXT DEFAULT 'Field Service Technician'\",\n      \"ALTER TABLE cursus_profile ADD COLUMN cover_industry TEXT DEFAULT 'Biotechnology/Agricultural Research'\",\n      \"ALTER TABLE cursus_profile ADD COLUMN nda_active INTEGER DEFAULT 1\",\n      \"ALTER TABLE cursus_profile ADD COLUMN dream_job TEXT\",\n      \"ALTER TABLE cursus_profile ADD COLUMN gap_analysis TEXT DEFAULT '[]'\",\n      \"ALTER TABLE cursus_profile ADD COLUMN target_roles TEXT DEFAULT '[]'\",\n      \"ALTER TABLE cursus_profile ADD COLUMN constraints_json TEXT DEFAULT '{}'\",\n    ];\n    for (const sql of profileCols) {\n      try { this.db.exec(sql); } catch { /* column already exists */ }\n    }\n\n    // ── New tables ──\n    this.db.exec(`\n      CREATE TABLE IF NOT EXISTS cursus_campaigns (\n        id           TEXT PRIMARY KEY,\n        name         TEXT NOT NULL,\n        target_role  TEXT NOT NULL,\n        phase        TEXT NOT NULL DEFAULT 'research' CHECK (phase IN ('research','applying','interviewing','negotiating','closed')),\n        milestones   TEXT NOT NULL DEFAULT '[]',\n        active       INTEGER NOT NULL DEFAULT 1,\n        created_at   TEXT NOT NULL\n      );\n\n      CREATE TABLE IF NOT EXISTS cursus_applications (\n        id           TEXT PRIMARY KEY,\n        campaign_id  TEXT NOT NULL,\n        company      TEXT NOT NULL,\n        role         TEXT NOT NULL,\n        url          TEXT,\n        salary_range TEXT,\n        match_score  INTEGER,\n        status       TEXT NOT NULL DEFAULT 'found' CHECK (status IN ('found','qualified','applied','responded','interviewing','closed')),\n        notes        TEXT,\n        applied_at   TEXT,\n        follow_up_at TEXT,\n        created_at   TEXT NOT NULL\n      );\n\n      CREATE TABLE IF NOT EXISTS cursus_resumes (\n        id               TEXT PRIMARY KEY,\n        profile_version  INTEGER,\n        base_resume      TEXT NOT NULL,\n        tailored_for     TEXT,\n        created_at       TEXT NOT NULL\n      );\n\n      CREATE TABLE IF NOT EXISTS cursus_outreach (\n        id              TEXT PRIMARY KEY,\n        application_id  TEXT,\n        type            TEXT NOT NULL CHECK (type IN ('email','cover_letter','recruiter')),\n        subject         TEXT NOT NULL,\n        body            TEXT NOT NULL,\n        status          TEXT NOT NULL DEFAULT 'staged' CHECK (status IN ('staged','approved','sent','replied')),\n        created_at      TEXT NOT NULL,\n        sent_at         TEXT,\n        gmail_thread_id TEXT\n      );\n\n      CREATE TABLE IF NOT EXISTS cursus_dux_sessions (\n        id                        TEXT PRIMARY KEY,\n        session_type              TEXT NOT NULL CHECK (session_type IN ('interview','checkin','role_assessment','discovery')),\n        messages                  TEXT NOT NULL DEFAULT '[]',\n        profile_version_generated INTEGER,\n        created_at                TEXT NOT NULL\n      );\n\n      CREATE INDEX IF NOT EXISTS idx_apps_campaign ON cursus_applications(campaign_id);\n      CREATE INDEX IF NOT EXISTS idx_apps_status ON cursus_applications(status);\n      CREATE INDEX IF NOT EXISTS idx_outreach_status ON cursus_outreach(status);\n      CREATE INDEX IF NOT EXISTS idx_outreach_app ON cursus_outreach(application_id);\n      CREATE INDEX IF NOT EXISTS idx_dux_sessions_type ON cursus_dux_sessions(session_type);\n    `);\n  }\n\n  // ── Profile (V2 extensions) ─────────────────────────────────────────────────\n\n  getProfileV2(): Record<string, unknown> | null {\n    return this.db.prepare(\"SELECT * FROM cursus_profile LIMIT 1\").get() as Record<string, unknown> | null;\n  }\n\n  updateProfileV2(patch: Record<string, unknown>): void {\n    const allowed = [\"dream_job\", \"gap_analysis\", \"target_roles\", \"constraints_json\", \"cover_employer\", \"cover_role\", \"cover_industry\", \"nda_active\"];\n    const fields: string[] = [];\n    const values: unknown[] = [];\n    for (const [k, v] of Object.entries(patch)) {\n      if (allowed.includes(k)) { fields.push(`${k} = ?`); values.push(v); }\n    }\n    if (fields.length === 0) return;\n    values.push(new Date().toISOString());\n    this.db.prepare(`UPDATE cursus_profile SET ${fields.join(\", \")}, updated_at = ? WHERE id = 1`).run(...values);\n  }\n\n  // ── Campaigns ───────────────────────────────────────────────────────────────\n\n  listCampaigns(): Campaign[] {\n    return this.db.prepare(\"SELECT * FROM cursus_campaigns ORDER BY created_at DESC\").all() as Campaign[];\n  }\n\n  getCampaign(id: string): Campaign | null {\n    return this.db.prepare(\"SELECT * FROM cursus_campaigns WHERE id = ?\").get(id) as Campaign | null;\n  }\n\n  createCampaign(name: string, targetRole: string): Campaign {\n    const id = randomUUID();\n    const now = new Date().toISOString();\n    this.db.prepare(\"INSERT INTO cursus_campaigns (id, name, target_role, created_at) VALUES (?, ?, ?, ?)\").run(id, name, targetRole, now);\n    return this.getCampaign(id)!;\n  }\n\n  updateCampaign(id: string, patch: Partial<Pick<Campaign, \"name\" | \"target_role\" | \"phase\" | \"milestones\" | \"active\">>): Campaign | null {\n    const fields: string[] = [];\n    const values: unknown[] = [];\n    for (const [k, v] of Object.entries(patch)) {\n      if ([\"name\", \"target_role\", \"phase\", \"milestones\", \"active\"].includes(k)) {\n        fields.push(`${k} = ?`);\n        values.push(k === \"active\" ? (v ? 1 : 0) : v);\n      }\n    }\n    if (fields.length === 0) return this.getCampaign(id);\n    values.push(id);\n    this.db.prepare(`UPDATE cursus_campaigns SET ${fields.join(\", \")} WHERE id = ?`).run(...values);\n    return this.getCampaign(id);\n  }\n\n  // ── Applications ────────────────────────────────────────────────────────────\n\n  listApplications(campaignId?: string): Application[] {\n    if (campaignId) return this.db.prepare(\"SELECT * FROM cursus_applications WHERE campaign_id = ? ORDER BY created_at DESC\").all(campaignId) as Application[];\n    return this.db.prepare(\"SELECT * FROM cursus_applications ORDER BY created_at DESC\").all() as Application[];\n  }\n\n  getApplication(id: string): Application | null {\n    return this.db.prepare(\"SELECT * FROM cursus_applications WHERE id = ?\").get(id) as Application | null;\n  }\n\n  createApplication(data: { campaign_id: string; company: string; role: string; url?: string; salary_range?: string; match_score?: number; notes?: string }): Application {\n    const id = randomUUID();\n    const now = new Date().toISOString();\n    this.db.prepare(\n      \"INSERT INTO cursus_applications (id, campaign_id, company, role, url, salary_range, match_score, notes, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)\"\n    ).run(id, data.campaign_id, data.company, data.role, data.url ?? null, data.salary_range ?? null, data.match_score ?? null, data.notes ?? null, now);\n    return this.getApplication(id)!;\n  }\n\n  updateApplication(id: string, patch: Partial<Pick<Application, \"status\" | \"notes\" | \"match_score\" | \"salary_range\" | \"applied_at\" | \"follow_up_at\" | \"url\">>): Application | null {\n    const fields: string[] = [];\n    const values: unknown[] = [];\n    for (const [k, v] of Object.entries(patch)) {\n      if ([\"status\", \"notes\", \"match_score\", \"salary_range\", \"applied_at\", \"follow_up_at\", \"url\"].includes(k)) {\n        fields.push(`${k} = ?`); values.push(v);\n      }\n    }\n    if (fields.length === 0) return this.getApplication(id);\n    values.push(id);\n    this.db.prepare(`UPDATE cursus_applications SET ${fields.join(\", \")} WHERE id = ?`).run(...values);\n    return this.getApplication(id);\n  }\n\n  countApplicationsByStatus(): Record<AppStatus, number> {\n    const rows = this.db.prepare(\"SELECT status, COUNT(*) as cnt FROM cursus_applications GROUP BY status\").all() as Array<{ status: AppStatus; cnt: number }>;\n    const counts: Record<string, number> = { found: 0, qualified: 0, applied: 0, responded: 0, interviewing: 0, closed: 0 };\n    for (const r of rows) counts[r.status] = r.cnt;\n    return counts as Record<AppStatus, number>;\n  }\n\n  // ── Resumes ─────────────────────────────────────────────────────────────────\n\n  listResumes(): Resume[] {\n    return this.db.prepare(\"SELECT * FROM cursus_resumes ORDER BY created_at DESC\").all() as Resume[];\n  }\n\n  createResume(baseResume: string, profileVersion?: number, tailoredFor?: string): Resume {\n    const id = randomUUID();\n    const now = new Date().toISOString();\n    this.db.prepare(\"INSERT INTO cursus_resumes (id, profile_version, base_resume, tailored_for, created_at) VALUES (?, ?, ?, ?, ?)\").run(id, profileVersion ?? null, baseResume, tailoredFor ?? null, now);\n    return this.db.prepare(\"SELECT * FROM cursus_resumes WHERE id = ?\").get(id) as Resume;\n  }\n\n  // ── Outreach ────────────────────────────────────────────────────────────────\n\n  listOutreach(status?: OutreachStatus): Outreach[] {\n    if (status) return this.db.prepare(\"SELECT * FROM cursus_outreach WHERE status = ? ORDER BY created_at DESC\").all(status) as Outreach[];\n    return this.db.prepare(\"SELECT * FROM cursus_outreach ORDER BY created_at DESC\").all() as Outreach[];\n  }\n\n  stageOutreach(data: { application_id?: string; type: OutreachType; subject: string; body: string }): Outreach {\n    const id = randomUUID();\n    const now = new Date().toISOString();\n    this.db.prepare(\n      \"INSERT INTO cursus_outreach (id, application_id, type, subject, body, status, created_at) VALUES (?, ?, ?, ?, ?, 'staged', ?)\"\n    ).run(id, data.application_id ?? null, data.type, data.subject, data.body, now);\n    return this.db.prepare(\"SELECT * FROM cursus_outreach WHERE id = ?\").get(id) as Outreach;\n  }\n\n  approveOutreach(id: string): Outreach | null {\n    // STEALTH: only staged → approved transition allowed\n    const existing = this.db.prepare(\"SELECT * FROM cursus_outreach WHERE id = ?\").get(id) as Outreach | null;\n    if (!existing || existing.status !== \"staged\") return null;\n    this.db.prepare(\"UPDATE cursus_outreach SET status = 'approved' WHERE id = ? AND status = 'staged'\").run(id);\n    return this.db.prepare(\"SELECT * FROM cursus_outreach WHERE id = ?\").get(id) as Outreach;\n  }\n\n  markOutreachSent(id: string, gmailThreadId?: string): Outreach | null {\n    // STEALTH: only approved → sent transition allowed — NEVER skip approval\n    const existing = this.db.prepare(\"SELECT * FROM cursus_outreach WHERE id = ?\").get(id) as Outreach | null;\n    if (!existing || existing.status !== \"approved\") return null;\n    const now = new Date().toISOString();\n    this.db.prepare(\"UPDATE cursus_outreach SET status = 'sent', sent_at = ?, gmail_thread_id = ? WHERE id = ? AND status = 'approved'\").run(now, gmailThreadId ?? null, id);\n    return this.db.prepare(\"SELECT * FROM cursus_outreach WHERE id = ?\").get(id) as Outreach;\n  }\n\n  markOutreachReplied(id: string): Outreach | null {\n    this.db.prepare(\"UPDATE cursus_outreach SET status = 'replied' WHERE id = ? AND status = 'sent'\").run(id);\n    return this.db.prepare(\"SELECT * FROM cursus_outreach WHERE id = ?\").get(id) as Outreach;\n  }\n\n  rejectOutreach(id: string): boolean {\n    return this.db.prepare(\"DELETE FROM cursus_outreach WHERE id = ? AND status = 'staged'\").run(id).changes > 0;\n  }\n\n  // ── Dux Sessions ────────────────────────────────────────────────────────────\n\n  listDuxSessions(): DuxSession[] {\n    return this.db.prepare(\"SELECT * FROM cursus_dux_sessions ORDER BY created_at DESC\").all() as DuxSession[];\n  }\n\n  getDuxSession(id: string): DuxSession | null {\n    return this.db.prepare(\"SELECT * FROM cursus_dux_sessions WHERE id = ?\").get(id) as DuxSession | null;\n  }\n\n  createDuxSession(sessionType: DuxSessionType): DuxSession {\n    const id = randomUUID();\n    const now = new Date().toISOString();\n    this.db.prepare(\"INSERT INTO cursus_dux_sessions (id, session_type, messages, created_at) VALUES (?, ?, '[]', ?)\").run(id, sessionType, now);\n    return this.getDuxSession(id)!;\n  }\n\n  appendDuxMessage(sessionId: string, role: \"user\" | \"assistant\", content: string): void {\n    const session = this.getDuxSession(sessionId);\n    if (!session) return;\n    const messages = JSON.parse(session.messages) as Array<{ role: string; content: string; timestamp: string }>;\n    messages.push({ role, content, timestamp: new Date().toISOString() });\n    this.db.prepare(\"UPDATE cursus_dux_sessions SET messages = ? WHERE id = ?\").run(JSON.stringify(messages), sessionId);\n  }\n\n  // ── Dashboard ───────────────────────────────────────────────────────────────\n\n  getDashboard(): DashboardStats {\n    const campaigns = this.listCampaigns();\n    const activeCampaign = campaigns.find(c => c.active) ?? null;\n    const counts = this.countApplicationsByStatus();\n    const totalApplications = Object.values(counts).reduce((a, b) => a + b, 0);\n\n    const outreachCounts = this.db.prepare(\"SELECT status, COUNT(*) as cnt FROM cursus_outreach GROUP BY status\").all() as Array<{ status: string; cnt: number }>;\n    const oc: Record<string, number> = {};\n    for (const r of outreachCounts) oc[r.status] = r.cnt;\n\n    const duxSessions = this.listDuxSessions();\n    const lastDux = duxSessions.length > 0 ? duxSessions[0]!.created_at : null;\n\n    // Recent activity: last 10 applications + outreach events\n    const recentApps = this.db.prepare(\"SELECT 'application' as type, company || ' — ' || role as detail, created_at as timestamp FROM cursus_applications ORDER BY created_at DESC LIMIT 5\").all() as Array<{ type: string; detail: string; timestamp: string }>;\n    const recentOutreach = this.db.prepare(\"SELECT 'outreach' as type, type || ': ' || subject as detail, created_at as timestamp FROM cursus_outreach ORDER BY created_at DESC LIMIT 5\").all() as Array<{ type: string; detail: string; timestamp: string }>;\n    const recentActivity = [...recentApps, ...recentOutreach].sort((a, b) => b.timestamp.localeCompare(a.timestamp)).slice(0, 10);\n\n    return {\n      activeCampaign,\n      applicationCounts: counts,\n      totalApplications,\n      pendingOutreach: oc[\"staged\"] ?? 0,\n      approvedOutreach: oc[\"approved\"] ?? 0,\n      sentOutreach: oc[\"sent\"] ?? 0,\n      repliedOutreach: oc[\"replied\"] ?? 0,\n      lastDuxSession: lastDux,\n      recentActivity,\n    };\n  }\n\n  close(): void {\n    this.db.close();\n  }\n}\n\n// ── Dux System Prompt ─────────────────────────────────────────────────────────\n\nexport const DUX_SYSTEM_PROMPT = `You are Dux, career counselor inside Squidley. You guide Jeff through his career transition with honesty and precision. You have access to his current profile, active campaigns, job market data, his uploaded resume, his projects, certifications, skills, and Squidley's memory of past sessions. When the user asks you to read or review their resume, reference the RESUME ON FILE section in your context — it is already loaded. You never fabricate job matches or inflate qualifications. Every claim you make about the job market or Jeff's qualifications is sourced from actual data or clearly marked as inference. You are direct, experienced, and genuinely invested in Jeff's success. When you identify a skill gap that Magister can address, you propose commissioning a learning campaign.\n\nPERSONALITY: Direct, experienced, respected — speak like a senior career advisor who has seen thousands of CVs. Challenge vague answers. Be honest about gaps. Celebrate real progress only — not performative.\n\nSTEALTH EMPLOYMENT COVER — ENFORCE IN ALL EXTERNAL-FACING CONTENT:\n- Current employer: \"Confidential — Plant Tissue Culture Laboratory (NDA)\"\n- Role: \"Field Service Technician supporting laboratory equipment and systems\"\n- Industry: \"Biotechnology/Agricultural Research\"\n- Cannot disclose employer name, specific clients, or proprietary processes due to NDA\n- All resumes, cover letters, and outreach must use this cover when current employment is referenced\n- NEVER reference copiers, printers, or the actual field service industry in any outreach\n- The 20+ years of technical experience is framed as: systems troubleshooting, electronics repair, precision equipment maintenance, and diagnostic methodology\n- Internal profile can show full history. External output always uses the cover.\n\nCAPABILITIES:\n- When you identify a skill gap, you can commission a Magister learning campaign for that certification or topic\n- You can search the job market, assess role fit, and recommend apply/skip/improve-first\n- You can generate or tailor resumes based on the current profile\n- You can draft outreach communications (always staged for approval, never auto-sent)\n\nAGENT COMMANDS — you can trigger these by including the exact tag in your response:\n- [RUN:cursus-job-search] — Triggers the Job Scout agent to scan for job listings matching the current campaign\n- [RUN:cursus-recruiter-search] — Triggers Recruiter Radar to find hiring managers and recruiters\n- [RUN:cursus-comms] — Triggers the Comms Drafter to write outreach emails\n- [RUN:cursus-resume-tailor] — Triggers the Resume Tailor to customize the resume for a specific role\n- [RUN:cursus-records] — Triggers the Job Log to update application tracking\n\nWhen the user asks you to search for jobs, find recruiters, draft emails, or tailor a resume, include the appropriate [RUN:agent-id] tag in your response. The system will detect it and execute the agent automatically. You will receive the results in the next turn.\n\nIMPORTANT: Only trigger agents when the user explicitly asks or when it's the natural next step in the conversation. Never trigger agents speculatively.\n\nBROWSER COMMANDS — you can control a browser to fill out job applications:\n- [BROWSE:url] — Opens a URL in the browser, takes a screenshot, returns page content. Use this to check a job listing.\n- [APPLY:url] — Navigates to a job application URL, analyzes the form, and stages fill/click/submit actions for Jeff's approval. Every form action requires approval before executing.\n- [APPROVE_BROWSER] — Approves and executes all pending browser actions.\n\nWhen the user asks you to apply to a job, fill out an application, or check a listing, include the appropriate tag. The system will execute the browser automation and return results. Jeff approves every form submission — nothing submits without his explicit approval.\n\nSTEALTH DOCTRINE: Nothing sends without Jeff's explicit approval. Outreach is staged, never auto-sent. Job search details are never surfaced in general conversation unless Jeff brings it up first.`;\n\n// ── Module ────────────────────────────────────────────────────────────────────\n\nlet db: CursusV2DB | null = null;\n\nexport function getCursusV2DB(): CursusV2DB {\n  if (!db) db = new CursusV2DB();\n  return db;\n}\n\nexport const CursusV2Module: SquidleyModule = {\n  manifest: {\n    id: \"squidley.experience.cursus-v2\",\n    name: \"Cursus V2\",\n    version: \"2.0.0\",\n    apiVersion: \"2.0.0\",\n    description: \"Career Change Command Center — Dux counselor, resume builder, job pipeline, Gmail integration\",\n    category: \"experience\",\n  },\n\n  dependencies: {\n    required: [],\n    optional: [\"squidley.system.provider-manager\", \"squidley.experience.magister\"],\n    versionRequirements: {},\n  },\n\n  config: { schema: {}, required: [], defaults: {} },\n  capabilities: [\"receipts.write\", \"fs.read\", \"fs.write\", \"network.outbound\"],\n  events: { subscribes: [], emits: [\"cursus.outreach.staged\", \"cursus.outreach.approved\", \"cursus.outreach.sent\"] },\n\n  async init(ctx: ModuleContext) {\n    db = new CursusV2DB();\n\n    ctx.registerService({\n      serviceId: \"cursus-v2\",\n      interfaceName: \"CursusV2\",\n      implementation: {\n        // Profile\n        getProfileV2:       () => db!.getProfileV2(),\n        updateProfileV2:    (patch: Record<string, unknown>) => db!.updateProfileV2(patch),\n        // Campaigns\n        listCampaigns:      () => db!.listCampaigns(),\n        getCampaign:        (id: string) => db!.getCampaign(id),\n        createCampaign:     (name: string, role: string) => db!.createCampaign(name, role),\n        updateCampaign:     (id: string, patch: Record<string, unknown>) => db!.updateCampaign(id, patch as any),\n        // Applications\n        listApplications:   (cid?: string) => db!.listApplications(cid),\n        getApplication:     (id: string) => db!.getApplication(id),\n        createApplication:  (data: Record<string, unknown>) => db!.createApplication(data as any),\n        updateApplication:  (id: string, patch: Record<string, unknown>) => db!.updateApplication(id, patch as any),\n        countByStatus:      () => db!.countApplicationsByStatus(),\n        // Resumes\n        listResumes:        () => db!.listResumes(),\n        createResume:       (text: string, ver?: number, tailored?: string) => db!.createResume(text, ver, tailored),\n        // Outreach (stealth enforced)\n        listOutreach:       (status?: string) => db!.listOutreach(status as any),\n        stageOutreach:      (data: Record<string, unknown>) => db!.stageOutreach(data as any),\n        approveOutreach:    (id: string) => db!.approveOutreach(id),\n        markOutreachSent:   (id: string, threadId?: string) => db!.markOutreachSent(id, threadId),\n        markOutreachReplied:(id: string) => db!.markOutreachReplied(id),\n        rejectOutreach:     (id: string) => db!.rejectOutreach(id),\n        // Dux\n        listDuxSessions:    () => db!.listDuxSessions(),\n        getDuxSession:      (id: string) => db!.getDuxSession(id),\n        createDuxSession:   (type: string) => db!.createDuxSession(type as any),\n        appendDuxMessage:   (sid: string, role: string, content: string) => db!.appendDuxMessage(sid, role as any, content),\n        // Dashboard\n        getDashboard:       () => db!.getDashboard(),\n      },\n    });\n\n    const dashboard = db.getDashboard();\n    ctx.log.info(`cursus-v2 initialized — ${dashboard.totalApplications} applications, ${dashboard.activeCampaign?.name ?? \"no active campaign\"}`);\n  },\n\n  async start() {},\n\n  async stop() {\n    db?.close();\n    db = null;\n  },\n\n  async healthCheck(): Promise<HealthReport> {\n    if (!db) return { status: \"degraded\", message: \"DB not initialized\" };\n    const dashboard = db.getDashboard();\n    return {\n      status: \"healthy\",\n      message: `${dashboard.totalApplications} apps, ${dashboard.pendingOutreach} staged outreach${dashboard.activeCampaign ? `, campaign: ${dashboard.activeCampaign.name}` : \"\"}`,\n      checks: { db: true },\n    };\n  },\n};\n",
