              "path": "modules/integrations/comfyui/index.ts",
              "content": "/**\n * Squidley V2 — ComfyUI Integration\n * ============================================================\n * Ported from V1. Image generation with VL feedback loop.\n *\n * Pipeline:\n *   1. Generate image via ComfyUI (SDXL)\n *   2. qwen3-vl:4b describes the result\n *   3. QC model scores against intent (gpt-4o-mini or local)\n *   4. If score fails → refine prompt → iterate (max 3x)\n *   5. Return final image + full iteration history\n *\n * Routes registered:\n *   POST /image/generate\n *   GET  /image/output/:filename  (proxy from ComfyUI)\n *   GET  /image/list\n *   GET  /image/status\n * ============================================================\n */\n\nimport { readdir } from \"node:fs/promises\";\nimport { basename, join } from \"node:path\";\nimport type { SquidleyModule, ModuleContext, HealthReport } from \"@squidley/core/sdk\";\n\nconst COMFYUI_URL     = (process.env[\"COMFYUI_URL\"]         ?? \"http://127.0.0.1:8188\").replace(/\\/+$/, \"\");\nconst OLLAMA_URL      = (process.env[\"OLLAMA_BASE_URL\"]      ?? \"http://127.0.0.1:11434\").replace(/\\/+$/, \"\");\nconst OUTPUT_DIR      = process.env[\"COMFYUI_OUTPUT_DIR\"]    ?? \"/mnt/ai/comfyui/output\";\nconst CHECKPOINT      = process.env[\"COMFYUI_CHECKPOINT\"]    ?? \"sd_xl_base_1.0.safetensors\";\nconst VL_MODEL        = process.env[\"SQUIDLEY_VL_MODEL\"]     ?? \"qwen3-vl:4b\";\nconst PROMPT_MODEL    = process.env[\"SQUIDLEY_PROMPT_MODEL\"] ?? \"qwen2.5:14b-instruct\";\n\n// ── ComfyUI helpers ───────────────────────────────────────────────────────────\n\nexport async function comfyuiReady(): Promise<boolean> {\n  try {\n    const r = await fetch(`${COMFYUI_URL}/system_stats`, { signal: AbortSignal.timeout(3_000) });\n    return r.ok;\n  } catch { return false; }\n}\n\nfunction buildSdxlWorkflow(prompt: string, negative: string, seed: number, steps: number, outputPrefix: string) {\n  return {\n    \"1\": { class_type: \"CheckpointLoaderSimple\", inputs: { ckpt_name: CHECKPOINT } },\n    \"2\": { class_type: \"CLIPTextEncode\", inputs: { text: prompt, clip: [\"1\", 1] } },\n    \"3\": { class_type: \"CLIPTextEncode\", inputs: { text: negative, clip: [\"1\", 1] } },\n    \"4\": { class_type: \"EmptyLatentImage\", inputs: { width: 1024, height: 1024, batch_size: 1 } },\n    \"5\": { class_type: \"KSampler\", inputs: { model: [\"1\", 0], positive: [\"2\", 0], negative: [\"3\", 0], latent_image: [\"4\", 0], seed, steps, cfg: 7.0, sampler_name: \"euler\", scheduler: \"normal\", denoise: 1.0 } },\n    \"6\": { class_type: \"VAEDecode\", inputs: { samples: [\"5\", 0], vae: [\"1\", 2] } },\n    \"7\": { class_type: \"SaveImage\", inputs: { images: [\"6\", 0], filename_prefix: outputPrefix } },\n  };\n}\n\nasync function generateImage(prompt: string, negative: string, seed: number, steps: number, outputPrefix: string): Promise<string> {\n  const workflow = buildSdxlWorkflow(prompt, negative, seed, steps, outputPrefix);\n  const submitResp = await fetch(`${COMFYUI_URL}/prompt`, {\n    method: \"POST\",\n    headers: { \"content-type\": \"application/json\" },\n    body: JSON.stringify({ prompt: workflow }),\n    signal: AbortSignal.timeout(10_000),\n  });\n  if (!submitResp.ok) throw new Error(`ComfyUI submit failed: ${submitResp.status}`);\n  const { prompt_id } = await submitResp.json() as { prompt_id: string };\n  if (!prompt_id) throw new Error(\"No prompt_id returned\");\n\n  // Poll for completion (max 4 min)\n  const started = Date.now();\n  while (Date.now() - started < 4 * 60_000) {\n    await new Promise(r => setTimeout(r, 2_000));\n    const histResp = await fetch(`${COMFYUI_URL}/history/${prompt_id}`, { signal: AbortSignal.timeout(5_000) });\n    if (!histResp.ok) continue;\n    const hist = await histResp.json() as Record<string, { outputs?: Record<string, { images?: Array<{ filename: string }> }> }>;\n    const entry = hist[prompt_id];\n    if (!entry?.outputs) continue;\n    for (const nodeOut of Object.values(entry.outputs)) {\n      if (nodeOut?.images?.[0]?.filename) return nodeOut.images[0].filename;\n    }\n  }\n  throw new Error(\"Timed out waiting for ComfyUI\");\n}\n\nasync function describeImage(filename: string): Promise<string> {\n  const viewResp = await fetch(`${COMFYUI_URL}/view?filename=${encodeURIComponent(filename)}`, { signal: AbortSignal.timeout(15_000) });\n  if (!viewResp.ok) throw new Error(`ComfyUI /view failed: ${viewResp.status}`);\n  const base64 = Buffer.from(await viewResp.arrayBuffer()).toString(\"base64\");\n\n  const resp = await fetch(`${OLLAMA_URL}/api/chat`, {\n    method: \"POST\",\n    headers: { \"content-type\": \"application/json\" },\n    body: JSON.stringify({\n      model: VL_MODEL,\n      messages: [{ role: \"user\", content: \"Describe this image concisely. Focus on: subject, colors, composition, style, any problems.\", images: [base64] }],\n      stream: false,\n      keep_alive: 0,  // unload immediately after use — VL models are too large to idle in VRAM\n      options: { temperature: 0.1, num_predict: 300 },\n    }),\n    signal: AbortSignal.timeout(60_000),\n  });\n  if (!resp.ok) throw new Error(`VL model failed: ${resp.status}`);\n  const data = await resp.json() as { message?: { content?: string } };\n  return String(data?.message?.content ?? \"\").trim();\n}\n\nasync function qcScore(intent: string, description: string, prompt: string): Promise<{ pass: boolean; notes: string; refined_prompt?: string }> {\n  const systemPrompt = `You are a QC judge for AI-generated images. Given the original intent, what was actually generated, and the prompt used, decide if the image meets the intent.\nRespond in JSON only: {\"pass\": true/false, \"notes\": \"brief explanation\", \"refined_prompt\": \"improved prompt if pass is false, omit if pass is true\"}`;\n  const userMsg = `Intent: ${intent}\\nActual description: ${description}\\nPrompt used: ${prompt}`;\n\n  // Try OpenAI first, fall back to local\n  const apiKey = (process.env[\"OPENAI_API_KEY\"] ?? \"\").trim();\n  if (apiKey.length > 10) {\n    const baseUrl = process.env[\"OPENAI_BASE_URL\"] ?? \"https://api.openai.com/v1\";\n    const resp = await fetch(`${baseUrl}/chat/completions`, {\n      method: \"POST\",\n      headers: { \"content-type\": \"application/json\", \"authorization\": `Bearer ${apiKey}` },\n      body: JSON.stringify({ model: \"gpt-4o-mini\", messages: [{ role: \"system\", content: systemPrompt }, { role: \"user\", content: userMsg }], temperature: 0.2, max_tokens: 300, response_format: { type: \"json_object\" } }),\n      signal: AbortSignal.timeout(30_000),\n    });\n    if (resp.ok) {\n      const data = await resp.json() as { choices?: Array<{ message?: { content?: string } }> };\n      return JSON.parse(String(data?.choices?.[0]?.message?.content ?? \"{}\")) as { pass: boolean; notes: string; refined_prompt?: string };\n    }\n  }\n\n  // Local fallback\n  const resp = await fetch(`${OLLAMA_URL}/api/generate`, {\n    method: \"POST\",\n    headers: { \"content-type\": \"application/json\" },\n    // keep_alive: 0 unloads the model immediately — PROMPT_MODEL is qwen2.5:14b-instruct\n    // by default, too big to idle in the 4070's 12GB VRAM alongside other workloads.\n    body: JSON.stringify({ model: PROMPT_MODEL, system: systemPrompt, prompt: userMsg, stream: false, format: \"json\", keep_alive: 0, options: { temperature: 0.2, num_predict: 300 } }),\n    signal: AbortSignal.timeout(60_000),\n  });\n  if (!resp.ok) return { pass: true, notes: \"QC fallback unavailable — accepting\" };\n  const data = await resp.json() as { response?: string };\n  try { return JSON.parse(String(data?.response ?? \"{}\")) as { pass: boolean; notes: string; refined_prompt?: string }; }\n  catch { return { pass: true, notes: \"QC parse failed — accepting\" }; }\n}\n\nasync function refinePrompt(originalPrompt: string, intent: string, vlDescription: string, userFeedback: string, qcNotes: string): Promise<string> {\n  const resp = await fetch(`${