es = await fetch(`${COMFYUI_URL}/prompt`, { signal: AbortSignal.timeout(2_000) });\n        if (qRes.ok) {\n          const qData = await qRes.json() as { exec_info?: { queue_remaining?: number } };\n          const queueSize = qData.exec_info?.queue_remaining ?? 0;\n          if (queueSize > 0) parts.push(`queue: ${queueSize}`);\n        }\n      } catch { /* queue check optional */ }\n\n      return { status: \"healthy\", message: parts.join(\" · \") };\n    } catch {\n      return { status: \"degraded\", message: \"ComfyUI not running — start with Docker or direct\", expectedDegraded: true };\n    }\n  },\n};\n",
