            "diff": "diff --git a/modules/system/memory/index.ts b/modules/system/memory/index.ts\nindex effaa6f..617ec38 100644\n--- a/modules/system/memory/index.ts\n+++ b/modules/system/memory/index.ts\n@@ -883,6 +883,10 @@ export const MemoryModule: SquidleyModule = {\n     const base = process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n     const memoryDir = process.env[\"SQUIDLEY_MEMORY_DIR\"] ?? `${base}/memory`;\n     const ollamaBase = process.env[\"OLLAMA_BASE_URL\"] ?? \"http://localhost:11434\";\n+    const sessionPersistence = process.env[\"SQUIDLEY_SESSION_PERSISTENCE\"] ?? \"disk\";\n+    if (sessionPersistence === \"disk\") {\n+      await memoryManager.sessionStore?.loadAllSessions();\n+    }\n \n     await memoryManager.init(ctx, memoryDir, ollamaBase);\n     await memoryManager.syncFromDisk();\n@@ -907,6 +911,7 @@ export const MemoryModule: SquidleyModule = {\n         getSessionResume: (id: string) => memoryManager.sessionStore?.getSessionResume(id) ?? null,\n         appendSessionMessage: (input: { sessionId: string; role: \"system\" | \"user\" | \"assistant\"; content: string; tokens?: number | null; modelUsed?: string | null; timestamp?: number }) => memoryManager.sessionStore?.appendMessage(input),\n         updateSession:    (id: string, patch: { name?: string; topic?: string; mood?: string; dna?: string; summary?: string; modelUsed?: string; lastActive?: number }) => memoryManager.sessionStore?.updateSession(id, patch) ?? null,\n+        persistSession:   (id: string) => memoryManager.sessionStore?.persistSession(id),\n         deleteSession:    (id: string) => memoryManager.sessionStore?.deleteSession(id) ?? { deleted: false, tier: null },\n         refreshSessionTopic: (id: string, latestClassification?: string | null) => memoryManager.sessionStore?.refreshTopic(id, latestClassification as any) ?? Promise.resolve(null),\n         refreshSessionMood: (id: string) => memoryManager.sessionStore?.refreshMood(id) ?? Promise.resolve(null),\n@@ -935,6 +940,9 @@ export const MemoryModule: SquidleyModule = {\n   },\n \n   async start() {\n+    if (memoryManager.sessionStore) {\n+      memoryManager.sessionStore.startAutoPersist();\n+    }\n     memoryManager.sessionStore?.startNightlyCompaction();\n \n     // Schedule session archival every 30 minutes if working memory has content\n@@ -969,6 +977,9 @@ export const MemoryModule: SquidleyModule = {\n   async stop() {\n     memoryManager.sessionStore?.stopNightlyCompaction();\n     // Archive on shutdown if there's anything in working memory\n+    if (memoryManager.sessionStore) {\n+      await memoryManager.sessionStore.persistAllSessions();\n+    }\n     await memoryManager.archiveSession(false);\n   },\n \n",
            "originalContent": "/**\n * Squidley V2 — Memory System\n * ============================================================\n * Five-tier memory architecture. Jarvis-level awareness.\n *\n * Tiers:\n *   working    — current session, in-memory, auto-summarized on end\n *   episodic   — past conversations as markdown + SQLite index\n *   semantic   — extracted facts: machines, projects, decisions, people\n *   project    — per-project namespaces injected when active\n *   preferences — how zen works, what he hates, his style\n *\n * Retrieval:\n *   1. Keyword search (fast, zero-dep)\n *   2. Embedding similarity via Ollama (nomic-embed-text, local, free)\n *   3. Merge, deduplicate, rank by relevance + recency\n *\n * Injection:\n *   - Max 2000 tokens injected per request\n *   - Project context first, then episodic, then semantic facts\n *   - Injected as second system message after persona prompt\n * ============================================================\n */\n\nimport { createRequire } from \"node:module\";\nimport { readFile, writeFile, readdir, mkdir } from \"node:fs/promises\";\nimport { existsSync } from \"node:fs\";\nimport { join, basename } from \"node:path\";\nimport Database from \"better-sqlite3\";\nimport type { SquidleyModule, ModuleContext, HealthReport } from \"@squidley/core/sdk\";\nimport { summarizeSession, formatSummaryAsMarkdown } from \"./summarizer.js\";\nimport { MemoryDAG, migrateToDAG, runDAGPass } from \"./dag.js\";\nimport { SessionStore } from \"./sessions.js\";\nimport { CanonicalMemoryService } from \"./store.js\";\nimport { runMemoryMaintenanceCycle } from \"./maintenance.js\";\n\nconst require = createRequire(import.meta.url);\nimport { sanitizePublicOutput } from \"./sanitize.js\";\nimport type {\n  MemoryCapsuleDocument,\n  MemoryConsolidationReport,\n  MemoryIndexDocument,\n  MemoryUseResolution,\n  MemoryVeritorSnapshot,\n  MemoryWriteInput,\n} from \"./types.js\";\n\n// ── Types ─────────────────────────────────────────────────────────────────────\n\nexport type MemoryTier = \"working\" | \"episodic\" | \"semantic\" | \"project\" | \"preferences\";\n\nexport interface MemoryEntry {\n  id: string;\n  tier: MemoryTier;\n  title: string;\n  content: string;\n  project?: string;\n  tags: string[];\n  createdAt: string;\n  updatedAt: string;\n  /** Embedding vector stored as JSON array */\n  embedding?: number[];\n  /** Relevance score assigned during retrieval */\n  score?: number;\n}\n\nexport interface WorkingMemoryMessage {\n  role: \"user\" | \"assistant\";\n  content: string;\n  timestamp: number;\n  model?: string;\n  tokensIn?: number;\n  tokensOut?: number;\n}\n\nexport interface MemoryContext {\n  entries: MemoryEntry[];\n  totalTokensEstimate: number;\n  injectionBlock: string;\n}\n\nexport interface MemoryWriteOptions {\n  tier: MemoryTier;\n  title: string;\n  content: string;\n  project?: string;\n  tags?: string[];\n}\n\n// ── Constants ─────────────────────────────────────────────────────────────────\n\nconst MAX_INJECT_CHARS   = 8_000;   // ~2000 tokens\nconst EMBEDDING_MODEL    = \"nomic-embed-text\";\nconst SIMILARITY_THRESH  = 0.72;\nconst MAX_RESULTS        = 6;\nconst CHARS_PER_TOKEN    = 4;\n\n// ── Embedding availability tracking ──────────────────────────────────────────\nlet _embeddingAvailable = false;\nlet _embeddingChecked = false;\nlet _searchMode: \"semantic\" | \"keyword\" = \"keyword\";\n\n// ── Keyword extraction ────────────────────────────────────────────────────────\n\nconst STOP_WORDS = new Set([\n  \"the\",\"a\",\"an\",\"and\",\"or\",\"but\",\"in\",\"on\",\"at\",\"to\",\"for\",\"of\",\"with\",\n  \"is\",\"are\",\"was\",\"were\",\"be\",\"been\",\"have\",\"has\",\"had\",\"do\",\"does\",\"did\",\n  \"will\",\"would\",\"could\",\"should\",\"may\",\"might\",\"shall\",\"can\",\"need\",\"must\",\n  \"i\",\"you\",\"he\",\"she\",\"it\",\"we\",\"they\",\"me\",\"him\",\"her\",\"us\",\"them\",\"my\",\n  \"your\",\"his\",\"its\",\"our\",\"their\",\"what\",\"which\",\"who\",\"how\",\"when\",\"where\",\n  \"why\",\"this\",\"that\",\"these\",\"those\",\"so\",\"if\",\"not\",\"no\",\"yes\",\"just\",\"also\",\n]);\n\nfunction extractKeywords(text: string): string[] {\n  return text\n    .toLowerCase()\n    .replace(/[^a-z0-9\\s-]/g, \" \")\n    .split(/\\s+/)\n    .filter(w => w.length > 2 && !STOP_WORDS.has(w))\n    .slice(0, 20);\n}\n\nfunction cosineSimilarity(a: number[], b: number[]): number {\n  if (a.length !== b.length) return 0;\n  let dot = 0, magA = 0, magB = 0;\n  for (let i = 0; i < a.length; i++) {\n    dot  += (a[i] ?? 0) * (b[i] ?? 0);\n    magA += (a[i] ?? 0) ** 2;\n    magB += (b[i] ?? 0) ** 2;\n  }\n  return magA && magB ? dot / (Math.sqrt(magA) * Math.sqrt(magB)) : 0;\n}\n\n// ── Memory Manager ────────────────────────────────────────────────────────────\n\nclass MemoryManager {\n  private memoryDir: string = \"\";\n  private db: InstanceType<typeof Database> | null = null;\n  private ollamaBase: string = \"http://localhost:11434\";\n  private ctx!: ModuleContext;\n  private canonicalMemory: CanonicalMemoryService | null = null;\n\n  /** Working memory — in-RAM, current session only */\n  private workingMemory: WorkingMemoryMessage[] = [];\n  private activeProject: string | null = null;\n  public sessionStore: SessionStore | null = null;\n\n  // ── Initialization ──────────────────────────────────────────────────────────\n\n  async init(ctx: ModuleContext, memoryDir: string, ollamaBase: string): Promise<void> {\n    this.ctx = ctx;\n    this.memoryDir = memoryDir;\n    this.ollamaBase = ollamaBase;\n\n    // Create tier directories\n    for (const tier of [\"working\",\"episodic\",\"semantic\",\"project\",\"preferences\"] as MemoryTier[]) {\n      await mkdir(join(memoryDir, tier), { recursive: true });\n    }\n\n    // Initialize SQLite\n    const dbPath = join(memoryDir, \"index.db\");\n    this.db = new Database(dbPath);\n    this.initDb();\n\n    this.sessionStore = new SessionStore({\n      db: this.db,\n      ctx,\n      memoryDir,\n      ollamaBase,\n      writeMemory: (options) => this.write(options),\n    });\n    this.sessionStore.initSchema();\n\n    const base = process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n    const stateRoot = process.env[\"SQUIDLEY_STATE_DIR\"] ?? join(base, \"state\");\n    this.canonicalMemory = new CanonicalMemoryService(join(stateRoot, \"memory\"), {\n      log: ctx.log,\n      receiptsDir: join(stateRoot, \"receipts\"),\n    });\n    await this.canonicalMemory.init({ repoRoot: base });\n\n    // Seed default semantic entries if fresh install\n    await this.seedDefaults();\n\n    // Run DAG migration (safe to run multiple times — idempotent)\n    try {\n      if (!MemoryDAG.isDAGMigrated()) {\n        migrateToDAG();\n        ctx.log.info(\"memory DAG schema migrated\");\n      }\n    } catch (err) {\n      if (!String(err).includes(\"duplicate column\")) {\n        ctx.log.warn(`DAG migration warning: ${String(err)}`);\n      }\n    }\n\n    // Probe embedding availability (non-blocking — sets _searchMode)\n    await this.probeEmbedding();\n\n    ctx.log.info(`memory system initialized — ${memoryDir} (search=${_searchMode})`);\n  }\n\n  private initDb(): void {\n    const db = this.db!;\n\n    db.exec(`\n      CREATE TABLE IF NOT EXISTS memory_entries (\n        id          TEXT PRIMARY KEY,\n        tier        TEXT NOT NULL,\n        title       TEXT NOT NULL,\n        content     TEXT NOT NULL,\n        project     TEXT,\n        tags        TEXT DEFAULT '[]',\n        created_at  TEXT NOT NULL,\n        updated_at  TEXT NOT NULL,\n        embedding   TEXT,\n        file_path   TEXT\n      );\n\n      CREATE VIRTUAL TABLE IF NOT EXISTS memory_fts\n        USING fts5(id UNINDEXED, title, content, tags, content=memory_entries, content_rowid=rowid);\n\n      CREATE TRIGGER IF NOT EXISTS memory_fts_insert AFTER INSERT ON memory_entries BEGIN\n        INSERT INTO memory_fts(rowid, id, title, content, tags)\n          VALUES (new.rowid, new.id, new.title, new.content, new.tags);\n      END;\n\n      CREATE TRIGGER IF NOT EXISTS memory_fts_update AFTER UPDATE ON memory_entries BEGIN\n        INSERT INTO memory_fts(memory_fts, rowid, id, title, content, tags)\n          VALUES ('delete', old.rowid, old.id, old.title, old.content, old.tags);\n        INSERT INTO memory_fts(rowid, id, title, content, tags)\n          VALUES (new.rowid, new.id, new.title, new.content, new.tags);\n      END;\n\n      CREATE TRIGGER IF NOT EXISTS memory_fts_delete AFTER DELETE ON memory_entries BEGIN\n        INSERT INTO memory_fts(memory_fts, rowid, id, title, content, tags)\n          VALUES ('delete', old.rowid, old.id, old.title, old.content, old.tags);\n      END;\n    `);\n  }\n\n  private async seedDefaults(): Promise<void> {\n    const db = this.db!;\n    const count = (db.prepare(\"SELECT COUNT(*) as n FROM memory_entries WHERE tier='semantic'\").get() as { n: number }).n;\n    if (count > 0) return;\n\n    // Only seed lab-specific data if running on Mushin (full V2).\n    // Squidley Lite gets an empty memory — user builds their own context.\n    const isLite = !process.env[\"OPENROUTER_API_KEY\"] && !process.env[\"ANTHROPIC_API_KEY\"];\n    if (isLite) {\n      this.ctx.log.info(\"Lite mode — skipping lab-specific memory seeds. Memory starts fresh.\");\n      return;\n    }\n\n    // Seed core semantic memory from what we know about the lab\n    const defaults: MemoryWriteOptions[] = [\n      {\n        tier: \"semantic\",\n        title: \"Lab machines\",\n        tags: [\"machines\", \"hardware\", \"infrastructure\"],\n        content: `# Lab Machines\n\n## Mushin (formerly ZenPop)\n- Role: Main development workstation, Squidley V2 host\n- OS: Debian 12 / Mushin OS\n- GPU: NVIDIA RTX 4070\n- CPU: Intel i7-13700K\n- RAM: 32GB\n- Storage: Three NVMe drives — nvme0n1 (OS), nvme1n1 (/mnt/games), nvme2n1 (/mnt/ai)\n- Network: 100.118.60.13 (Tailscale)\n- Squidley V2: /mnt/ai/squidley-v2, port 18791 (API), port 3002 (UI)\n\n## Pop Tart\n- Role: Experimental machine, Krakzen host, red team attacker\n- OS: Debian / Pop!_OS\n- GPU: AMD Radeon RX 6800 (16GB VRAM)\n- CPU: Intel i7 ~10th gen\n- RAM: 32GB DDR5\n- Services: Jellyfin, Krakzen, Zen Council (parked)\n- Network: Tailscale connected\n- Model capacity: Comfortably runs 14B class models`,\n      },\n      {\n        tier: \"semantic\",\n        title: \"Active projects\",\n        tags: [\"projects\", \"architecture\", \"portfolio\"],\n        content: `# Active Projects\n\n## Squidley V2\n- Status: Active build — in development\n- Location: /mnt/ai/squidley-v2\n- Purpose: Local-first AI orchestration platform — the blue team / defender\n- Stack: TypeScript, Next.js, Fastify, pnpm workspaces\n- Key features: streaming chat, 5 providers, prompt injection defense, receipts, memory, diagnostics\n- Design system: Bioluminescent dark theme, Squidley PNG watermark centered\n\n## Krakzen\n- Status: V1 foundation complete on Pop Tart\n- Location: /hogwarts/AI/krakzen\n- Purpose: AI-specific security testing — prompt injection, jailbreaking, LLM manipulation\n- Status: V1 = trainer with guardrails; V2 = full red team (gated on demonstrated knowledge)\n- Built with: GPT (plan to migrate to Claude)\n\n## Archivum\n- Status: Vision captured — sleeper product\n- Purpose: Sovereign personal knowledge base — intake anything, auto-organize, semantic recall\n- Note: This IS the memory system's long-term product form\n\n## Tenticode\n- Status: Designed — build engine\n- Purpose: inspect → plan → patch → review → verify → apply\n- Note: Standalone product, separate repo`,\n      },\n      {\n        tier: \"preferences\",\n        title: \"How zen works\",\n        tags: [\"preferences\", \"workflow\", \"communication\"],\n        content: `# How Zen Works\n\n## Background\n- 20+ years field service technician (copiers, printers, hardware)\n- Former Air Force AGE (Aerospace Ground Equipment) mechanic\n- Self-taught AI systems developer — 9 months\n- Career transition target: Tier 2 tech support → AI Security Engineer\n\n## Working style\n- Full file replacements preferred — never partial patches to apply manually\n- Peer-level engagement — not a student, a builder\n- Honest assessment over encouragement — tell the truth\n- Thinks in systems and projects — connect advice to the bigger picture\n- Obsessive builder — never burned out, fires on all cylinders\n- Military precision — documentation, systematic thinking are natural\n\n## Technical preferences\n- Local-first always\n- Tools over tokens\n- Every action produces a receipt\n- No raw shell access to models\n- Full cost transparency\n\n## Things that matter\n- Job search is completely stealth — never suggest anything that could expose it\n- Money is strategic — never suggest paid tools casually\n- Finds the work genuinely fulfilling — protect that energy\n- Building a portfolio for career transition — every project has resume value`,\n      },\n      {\n        tier: \"semantic\",\n        title: \"Architecture decisions log\",\n        tags: [\"decisions\", \"architecture\", \"v2\"],\n        content: `# Architecture Decisions\n\n## Squidley V2 — Locked Decisions\n- Module discovery: file-based manifest.json in each module dir\n- Event bus: in-process EventEmitter with receipt hooks\n- UI contributions: boot-time static, queryable at runtime\n- Boot model: restart to add/remove modules — no hot-swap (like a receiver)\n- Persona system: pure data — system prompt, tone, name, theme only\n- Core footprint: Pi/phone deployable\n- Repos: four separate repos (Squidley, Krakzen, Archivum, Tenticode)\n- Design system: bioluminescent dark — locked v4, DO NOT redesign\n\n## Key Principles\n- Receiver analogy: turn off before adding modules\n- Chimp painting aesthetic: dark neutral base, precise color pops\n- Squidley meditates behind the UI — front and center\n- Memory is one of her most important features — must be Jarvis-level`,\n      },\n    ];\n\n    for (const entry of defaults) {\n      await this.write(entry);\n    }\n  }\n\n  // ── Write ───────────────────────────────────────────────────────────────────\n\n  async write(options: MemoryWriteOptions): Promise<string> {\n    const id = `${options.tier}-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;\n    const now = new Date().toISOString();\n    const tags = options.tags ?? [];\n    const filename = `${options.title.toLowerCase().replace(/[^a-z0-9]+/g,\"-\").slice(0,50)}.md`;\n    const tierDir = join(this.memoryDir, options.tier, ...(options.project ? [options.project] : []));\n    await mkdir(tierDir, { recursive: true });\n    const filePath = join(tierDir, filename);\n\n    // Write markdown file\n    const mdContent = [\n      `# ${options.title}`,\n      `_tier: ${options.tier} | tags: ${tags.join(\", \")} | updated: ${now}_`,\n      \"\",\n      options.content,\n    ].join(\"\\n\");\n    await writeFile(filePath, mdContent, \"utf-8\");\n\n    // Try to get embedding (non-blocking — fails gracefully if Ollama not running)\n    let embedding: number[] | undefined;\n    try {\n      embedding = await this.embed(options.content.slice(0, 2000));\n    } catch { /* ollama not available — skip */ }\n\n    // Upsert in SQLite\n    const db = this.db!;\n    const existing = db.prepare(\"SELECT id FROM memory_entries WHERE file_path = ?\").get(filePath) as { id: string } | undefined;\n\n    if (existing) {\n      db.prepare(`\n        UPDATE memory_entries SET title=?, content=?, tags=?, updated_at=?, embedding=?, project=?\n        WHERE file_path=?\n      `).run(options.title, options.content, JSON.stringify(tags), now,\n             embedding ? JSON.stringify(embedding) : null,\n             options.project ?? null, filePath);\n      return existing.id;\n    } else {\n      db.prepare(`\n        INSERT INTO memory_entries (id, tier, title, content, project, tags, created_at, updated_at, embedding, file_path)\n        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)\n      `).run(id, options.tier, options.title, options.content,\n             options.project ?? null, JSON.stringify(tags),\n             now, now,\n             embedding ? JSON.stringify(embedding) : null,\n             filePath);\n      return id;\n    }\n  }\n\n  // ── Retrieve ────────────────────────────────────────────────────────────────\n\n  async retrieve(query: string, project?: string): Promise<MemoryContext> {\n    const keywords = extractKeywords(query);\n    const results = new Map<string, MemoryEntry & { score: number }>();\n\n    // Layer 1: FTS keyword search\n    if (keywords.length > 0) {\n      // Use prefix matching (k*) for short terms, exact for longer ones\n      const ftsQuery = keywords.map(k => k.length <= 4 ? `${k}*` : `\"${k}\"`).join(\" OR \");\n      try {\n        const rows = this.db!.prepare(`\n          SELECT e.*, rank as fts_rank\n          FROM memory_entries e\n          JOIN memory_fts f ON e.id = f.id\n          WHERE memory_fts MATCH ?\n          ${project ? \"AND (e.project = ? OR e.project IS NULL)\" : \"\"}\n          ORDER BY rank\n          LIMIT 20\n        `).all(ftsQuery, ...(project ? [project] : [])) as Array<Record<string, unknown>>;\n\n        for (const row of rows) {\n          const entry = rowToEntry(row);\n          results.set(entry.id, { ...entry, score: 1.0 - (Number(row[\"fts_rank\"] ?? 0) / 10) });\n        }\n      } catch { /* fts error — continue */ }\n    }\n\n    // Layer 2: Embedding similarity for gaps\n    let queryEmbedding: number[] | undefined;\n    try {\n      queryEmbedding = await this.embed(query.slice(0, 500));\n    } catch { /* ollama not running */ }\n\n    if (queryEmbedding) {\n      const allRows = this.db!.prepare(`\n        SELECT * FROM memory_entries WHERE embedding IS NOT NULL\n        ${project ? \"AND (project = ? OR project IS NULL)\" : \"\"}\n      `).all(...(project ? [project] : [])) as Array<Record<string, unknown>>;\n\n      for (const row of allRows) {\n        if (results.has(row[\"id\"] as string)) continue; // already found by FTS\n        try {\n          const emb = JSON.parse(row[\"embedding\"] as string) as number[];\n          const sim = cosineSimilarity(queryEmbedding, emb);\n          if (sim >= SIMILARITY_THRESH) {\n            const entry = rowToEntry(row);\n            results.set(entry.id, { ...entry, score: sim });\n          }\n        } catch { /* skip malformed embedding */ }\n      }\n    }\n\n    // Layer 3: Always include active project memory + preferences AND the\n    // ambient `current_activity` slot written by the screen-watcher module\n    // (when enabled). The slot is upserted-by-title so there's at most one\n    // row at any given moment.\n    const alwaysInclude = this.db!.prepare(`\n      SELECT * FROM memory_entries\n      WHERE tier IN ('preferences')\n         OR (tier = 'working' AND title = 'current_activity')\n      ${project ? \"OR (tier = 'project' AND project = ?)\" : \"\"}\n      LIMIT 4\n    `).all(...(project ? [project] : [])) as Array<Record<string, unknown>>;\n\n    for (const row of alwaysInclude) {\n      if (!results.has(row[\"id\"] as string)) {\n        results.set(row[\"id\"] as string, { ...rowToEntry(row), score: 0.5 });\n      }\n    }\n\n    // Rank, deduplicate, trim to budget\n    const ranked = [...results.values()]\n      .sort((a, b) => b.score - a.score)\n      .slice(0, MAX_RESULTS);\n\n    let canonicalBlock = \"\";\n    if (this.canonicalMemory) {\n      try {\n        const canonical = await this.canonicalMemory.retrieveHints(query);\n        canonicalBlock = canonical.injectionBlock.trim();\n      } catch (err) {\n        this.ctx.log.warn(`canonical memory hint retrieval failed: ${String(err)}`);\n      }\n    }\n\n    // Build injection block\n    const injectionParts: string[] = [\n      ...(canonicalBlock ? [canonicalBlock, \"\"] : []),\n      \"# Squidley Memory Context\",\n      `_Retrieved ${ranked.length} relevant long-form memories_`,\n      \"\",\n    ];\n\n    let charCount = injectionParts.join(\"\\n\").length;\n\n    for (const entry of ranked) {\n      const section = [`## ${entry.title}`, `_${entry.tier}${entry.project ? ` · ${entry.project}` : \"\"}_`, \"\", entry.content, \"\"].join(\"\\n\");\n      if (charCount + section.length > MAX_INJECT_CHARS) break;\n      injectionParts.push(section);\n      charCount += section.length;\n    }\n\n    const injectionBlock = injectionParts.join(\"\\n\");\n\n    return {\n      entries: ranked,\n      totalTokensEstimate: Math.ceil(charCount / CHARS_PER_TOKEN),\n      injectionBlock,\n    };\n  }\n\n  /**\n   * Look up a single memory entry by id. Returns null if not found or if the\n   * db is uninitialized. Used by the chat-callable `memory.get` tool.\n   */\n  getEntryById(id: string): MemoryEntry | null {\n    if (!this.db) return null;\n    try {\n      const row = this.db\n        .prepare(\"SELECT * FROM memory_entries WHERE id = ? LIMIT 1\")\n        .get(id) as Record<string, unknown> | undefined;\n      if (!row) return null;\n      return rowToEntry(row);\n    } catch {\n      return null;\n    }\n  }\n\n  /**\n   * Run the retrieval pipeline and return just the ranked entries, optionally\n   * filtered by tier and capped at `topK`. Used by the chat-callable\n   * `memory.search` tool — thin wrapper so we don't duplicate the retrieval\n   * logic, but we strip the MemoryContext injection-block wrapping.\n   */\n  async searchEntries(opts: {\n    query: string;\n    project?: string | undefined;\n    tier?: MemoryTier | undefined;\n    topK?: number | undefined;\n  }): Promise<MemoryEntry[]> {\n    const ctx = await this.retrieve(opts.query, opts.project);\n    let entries = ctx.entries;\n    if (opts.tier) entries = entries.filter((e) => e.tier === opts.tier);\n    const k = Math.max(1, Math.min(opts.topK ?? 5, MAX_RESULTS));\n    return entries.slice(0, k);\n  }\n\n  // ── Working memory ──────────────────────────────────────────────────────────\n\n  addToWorking(msg: WorkingMemoryMessage): void {\n    this.workingMemory.push(msg);\n    // Keep last 100 messages in working memory\n    if (this.workingMemory.length > 100) {\n      this.workingMemory = this.workingMemory.slice(-100);\n    }\n  }\n\n  getWorkingMemory(): WorkingMemoryMessage[] {\n    return [...this.workingMemory];\n  }\n\n  setActiveProject(project: string | null): void {\n    this.activeProject = project;\n  }\n\n  getActiveProject(): string | null {\n    return this.activeProject;\n  }\n\n  /**\n   * Archive working memory to episodic.\n   * Summarizes the conversation and extracts key facts.\n   * Called at end of session or when context window is getting full.\n   */\n  async archiveSession(summarize: boolean = true): Promise<void> {\n    if (this.workingMemory.length < 2) return;\n\n    const sessionDate = new Date().toISOString().split(\"T\")[0] ?? new Date().toDateString();\n    const msgCount = this.workingMemory.length;\n    const messagesSnapshot = [...this.workingMemory];\n\n    let content: string;\n    let tags = [\"session\", \"auto-archived\", sessionDate];\n\n    if (summarize) {\n      this.ctx.log.info(`summarizing session — ${msgCount} messages via local model`);\n      try {\n        const summary = await summarizeSession(messagesSnapshot);\n        content = formatSummaryAsMarkdown(summary);\n        tags = [...tags, ...summary.entities.projects.slice(0, 3)];\n\n        // Promote new facts to semantic memory\n        for (const fact of summary.newFacts.slice(0, 5)) {\n          await this.write({\n            tier: \"semantic\",\n            title: `Fact — ${sessionDate}`,\n            content: fact,\n            ...(this.activeProject ? { project: this.activeProject } : {}),\n            tags: [\"auto-extracted\", sessionDate],\n          });\n        }\n        this.ctx.log.info(`session summarized — decisions: ${summary.decisions.length}, facts: ${summary.newFacts.length}, actions: ${summary.actionItems.length}`);\n      } catch (err) {\n        // Summarization failed — fall back to raw transcript\n        this.ctx.log.warn(`summarization failed, saving raw: ${String(err)}`);\n        const transcript = messagesSnapshot\n          .map(m => `**${m.role === \"user\" ? \"zen\" : \"squidley\"}**: ${m.content}`)\n          .join(\"\\n\\n\");\n        content = [`## Session ${sessionDate} — ${msgCount} messages`, \"\", transcript].join(\"\\n\");\n      }\n    } else {\n      const transcript = messagesSnapshot\n        .map(m => `**${m.role === \"user\" ? \"zen\" : \"squidley\"}**: ${m.content}`)\n        .join(\"\\n\\n\");\n      content = [`## Session ${sessionDate} — ${msgCount} messages (raw)`, \"\", transcript].join(\"\\n\");\n    }\n\n    await this.write({\n      tier: \"episodic\",\n      title: `Session ${sessionDate}`,\n      content,\n      ...(this.activeProject ? { project: this.activeProject } : {}),\n      tags,\n    });\n\n    this.ctx.log.info(`session archived — ${msgCount} messages → episodic memory`);\n    this.workingMemory = [];\n  }\n\n  // ── Embedding via Ollama ────────────────────────────────────────────────────\n\n  private async embed(text: string): Promise<number[]> {\n    const res = await fetch(`${this.ollamaBase}/api/embeddings`, {\n      method: \"POST\",\n      headers: { \"Content-Type\": \"application/json\" },\n      body: JSON.stringify({ model: EMBEDDING_MODEL, prompt: text }),\n      signal: AbortSignal.timeout(5000),\n    });\n    if (!res.ok) throw new Error(`Ollama embedding ${res.status}`);\n    const data = await res.json() as { embedding: number[] };\n    if (!_embeddingAvailable) {\n      _embeddingAvailable = true;\n      _searchMode = \"semantic\";\n      this.ctx.log.info(`semantic search enabled — ${EMBEDDING_MODEL} via Ollama`);\n    }\n    return data.embedding;\n  }\n\n  /** Probe embedding availability at startup — sets mode without blocking */\n  private async probeEmbedding(): Promise<void> {\n    if (_embeddingChecked) return;\n    _embeddingChecked = true;\n    try {\n      await this.embed(\"test\");\n      // _embeddingAvailable set inside embed() on success\n    } catch {\n      _embeddingAvailable = false;\n      _searchMode = \"keyword\";\n      this.ctx.log.info(\"Vector search unavailable — using keyword search (install ollama nomic-embed-text for better results)\");\n    }\n  }\n\n  /** Get health info for /memoria/health endpoint */\n  getHealthInfo(): {\n    ok: boolean;\n    mode: \"keyword\" | \"semantic\";\n    embeddingModel: string | null;\n    entryCount: number;\n    dbSizeBytes: number;\n    setupHints: string[];\n  } {\n    let entryCount = 0;\n    let dbSizeBytes = 0;\n    try {\n      const row = this.db!.prepare(\"SELECT COUNT(*) as n FROM memory_entries\").get() as { n: number };\n      entryCount = row.n;\n    } catch { /* db may not be ready */ }\n\n    try {\n      const { statSync } = require(\"node:fs\") as typeof import(\"node:fs\");\n      const dbPath = join(this.memoryDir, \"index.db\");\n      dbSizeBytes = statSync(dbPath).size;\n    } catch { /* file not found */ }\n\n    const hints: string[] = [];\n    if (!_embeddingAvailable) {\n      hints.push(\"ollama pull nomic-embed-text for semantic search\");\n    }\n\n    return {\n      ok: !!this.db,\n      mode: _searchMode,\n      embeddingModel: _embeddingAvailable ? EMBEDDING_MODEL : null,\n      entryCount,\n      dbSizeBytes,\n      setupHints: hints,\n    };\n  }\n\n  async getCanonicalIndex(): Promise<MemoryIndexDocument> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.getIndex();\n  }\n\n  async getMemoryCapsule(topic: string): Promise<MemoryCapsuleDocument | null> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.getCapsule(topic);\n  }\n\n  async remember(input: MemoryWriteInput) {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.remember(input);\n  }\n\n  async runCanonicalConsolidation(trigger: string = \"manual\"): Promise<MemoryConsolidationReport> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.consolidate(trigger);\n  }\n\n  async runMemoryMaintenanceCycle(trigger: string = \"background\"): Promise<MemoryConsolidationReport> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return runMemoryMaintenanceCycle(this.canonicalMemory, trigger);\n  }\n\n  async listStaleMemory() {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.listStale();\n  }\n\n  async listMemoryContradictions() {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.listContradictions();\n  }\n\n  async listMemoryOpenLoops() {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.listOpenLoops();\n  }\n\n  async getPublicCanonicalIndex(): Promise<MemoryIndexDocument> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.getPublicIndex();\n  }\n\n  async resolveMemoryForUse(topic: string, itemId: string, requireVerification: boolean): Promise<MemoryUseResolution | null> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    const capsule = await this.canonicalMemory.getCapsule(topic);\n    const item = capsule?.items.find((candidate) => candidate.id === itemId) ?? null;\n    if (!item) return null;\n    return this.canonicalMemory.resolveMemoryForUse(item, { requireVerification });\n  }\n\n  async getVeritorMemorySnapshot(): Promise<MemoryVeritorSnapshot> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.getVeritorSnapshot();\n  }\n\n  // ── Load from disk ──────────────────────────────────────────────────────────\n  /**\n   * Sync markdown files on disk into SQLite on startup.\n   * Handles files added manually outside the app.\n   */\n  async syncFromDisk(): Promise<void> {\n    const tiers: MemoryTier[] = [\"episodic\",\"semantic\",\"project\",\"preferences\"];\n    let synced = 0;\n\n    for (const tier of tiers) {\n      const tierDir = join(this.memoryDir, tier);\n      if (!existsSync(tierDir)) continue;\n\n      await this.syncDir(tierDir, tier, undefined);\n    }\n\n    this.ctx.log.info(`memory sync complete — ${synced} files`);\n  }\n\n  private async syncDir(dir: string, tier: MemoryTier, project: string | undefined): Promise<void> {\n    let entries: string[];\n    try { entries = await readdir(dir); } catch { return; }\n\n    for (const entry of entries) {\n      const fullPath = join(dir, entry);\n      if (entry.endsWith(\".md\")) {\n        const existing = this.db!.prepare(\"SELECT id FROM memory_entries WHERE file_path = ?\").get(fullPath);\n        if (!existing) {\n          const content = await readFile(fullPath, \"utf-8\").catch(() => \"\");\n          const title = basename(entry, \".md\").replace(/-/g, \" \");\n          await this.write({ tier, title, content, ...(project ? { project } : {}), tags: [] });\n        }\n      } else if (!entry.includes(\".\")) {\n        // Subdirectory — treat as project namespace\n        await this.syncDir(fullPath, tier, entry);\n      }\n    }\n  }\n}\n\n// ── Helper ────────────────────────────────────────────────────────────────────\n\nfunction rowToEntry(row: Record<string, unknown>): MemoryEntry {\n  return {\n    id: row[\"id\"] as string,\n    tier: row[\"tier\"] as MemoryTier,\n    title: row[\"title\"] as string,\n    content: row[\"content\"] as string,\n    ...(row[\"project\"] ? { project: row[\"project\"] as string } : {}),\n    tags: JSON.parse((row[\"tags\"] as string) ?? \"[]\") as string[],\n    createdAt: row[\"created_at\"] as string,\n    updatedAt: row[\"updated_at\"] as string,\n    ...(row[\"embedding\"] ? { embedding: JSON.parse(row[\"embedding\"] as string) as number[] } : {}),\n  };\n}\n\n// ── Singleton ─────────────────────────────────────────────────────────────────\n\nexport const memoryManager = new MemoryManager();\n\n// ── Module definition ─────────────────────────────────────────────────────────\n\nexport const MemoryModule: SquidleyModule = {\n  manifest: {\n    id: \"squidley.system.memory\",\n    name: \"Memory\",\n    version: \"2.0.0\",\n    apiVersion: \"2.0.0\",\n    description: \"Five-tier Jarvis-level memory — working, episodic, semantic, project, preferences\",\n    category: \"system\",\n  },\n\n  dependencies: {\n    required: [],\n    optional: [\"squidley.integration.provider-ollama\"],\n    versionRequirements: {},\n  },\n\n  config: {\n    schema: {\n      memoryDir: { type: \"string\", description: \"Directory for memory storage\", required: false },\n      ollamaBase: { type: \"string\", description: \"Ollama base URL for embeddings\", required: false },\n    },\n    required: [],\n    defaults: {},\n  },\n\n  capabilities: [\"fs.read\", \"fs.write\", \"memory.read\", \"memory.write\", \"network.outbound\"],\n  events: { subscribes: [\"platform.ready\"], emits: [\"memory.retrieved\", \"memory.written\", \"session.archived\"] },\n\n  contract: {\n    promise: \"Store and retrieve facts, decisions, and session context across conversations\",\n    proofPath: \"receipts — every read/write logged; memoria.db inspectable\",\n    degradedBehavior: \"Falls back to keyword search if embeddings unavailable — retrieval less precise but functional\",\n    failureOwner: \"memoria\",\n  },\n\n  async init(ctx: ModuleContext) {\n    const base = process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n    const memoryDir = process.env[\"SQUIDLEY_MEMORY_DIR\"] ?? `${base}/memory`;\n    const ollamaBase = process.env[\"OLLAMA_BASE_URL\"] ?? \"http://localhost:11434\";\n\n    await memoryManager.init(ctx, memoryDir, ollamaBase);\n    await memoryManager.syncFromDisk();\n\n    // Register memory service for other modules\n    ctx.registerService({\n      serviceId: \"memory\",\n      interfaceName: \"MemoryManager\",\n      implementation: {\n        retrieve:         (query: string, project?: string) => memoryManager.retrieve(query, project),\n        searchEntries:    (opts: { query: string; project?: string; tier?: MemoryTier; topK?: number }) => memoryManager.searchEntries(opts),\n        getEntryById:     (id: string) => memoryManager.getEntryById(id),\n        write:            (opts: MemoryWriteOptions) => memoryManager.write(opts),\n        addToWorking:     (msg: WorkingMemoryMessage) => memoryManager.addToWorking(msg),\n        getWorkingMemory: () => memoryManager.getWorkingMemory(),\n        archiveSession:   (summarize?: boolean) => memoryManager.archiveSession(summarize),\n        setActiveProject: (p: string | null) => memoryManager.setActiveProject(p),\n        getActiveProject: () => memoryManager.getActiveProject(),\n        createSession:    (input?: { name?: string; topic?: string; modelUsed?: string }) => memoryManager.sessionStore?.createSession(input),\n        listHotSessions:  () => memoryManager.sessionStore?.listHotSessions() ?? [],\n        getSession:       (id: string) => memoryManager.sessionStore?.getSession(id) ?? null,\n        getSessionResume: (id: string) => memoryManager.sessionStore?.getSessionResume(id) ?? null,\n        appendSessionMessage: (input: { sessionId: string; role: \"system\" | \"user\" | \"assistant\"; content: string; tokens?: number | null; modelUsed?: string | null; timestamp?: number }) => memoryManager.sessionStore?.appendMessage(input),\n        updateSession:    (id: string, patch: { name?: string; topic?: string; mood?: string; dna?: string; summary?: string; modelUsed?: string; lastActive?: number }) => memoryManager.sessionStore?.updateSession(id, patch) ?? null,\n        deleteSession:    (id: string) => memoryManager.sessionStore?.deleteSession(id) ?? { deleted: false, tier: null },\n        refreshSessionTopic: (id: string, latestClassification?: string | null) => memoryManager.sessionStore?.refreshTopic(id, latestClassification as any) ?? Promise.resolve(null),\n        refreshSessionMood: (id: string) => memoryManager.sessionStore?.refreshMood(id) ?? Promise.resolve(null),\n        autoNameSession:  (id: string) => memoryManager.sessionStore?.autoNameSession(id) ?? Promise.resolve(null),\n        runNightlyCompaction: () => memoryManager.sessionStore?.runNightlyCompaction() ?? Promise.resolve(),\n        runDAGPass:       (batchSize?: number) => runDAGPass(batchSize),\n        getDAGStats:      () => { const dag = new MemoryDAG(); const stats = dag.getStats(); dag.close(); return stats; },\n        traceSources:     (id: string) => { const dag = new MemoryDAG(); const r = dag.traceSources(id); dag.close(); return r; },\n        getHealthInfo:    () => memoryManager.getHealthInfo(),\n        getCanonicalIndex: () => memoryManager.getCanonicalIndex(),\n        getMemoryCapsule: (topic: string) => memoryManager.getMemoryCapsule(topic),\n        remember: (input: MemoryWriteInput) => memoryManager.remember(input),\n        runCanonicalConsolidation: (trigger?: string) => memoryManager.runCanonicalConsolidation(trigger),\n        runMemoryMaintenanceCycle: (trigger?: string) => memoryManager.runMemoryMaintenanceCycle(trigger),\n        listStaleMemory: () => memoryManager.listStaleMemory(),\n        listMemoryContradictions: () => memoryManager.listMemoryContradictions(),\n        listMemoryOpenLoops: () => memoryManager.listMemoryOpenLoops(),\n        getPublicCanonicalIndex: () => memoryManager.getPublicCanonicalIndex(),\n        resolveMemoryForUse: (topic: string, itemId: string, requireVerification: boolean) => memoryManager.resolveMemoryForUse(topic, itemId, requireVerification),\n        getVeritorMemorySnapshot: () => memoryManager.getVeritorMemorySnapshot(),\n        sanitizePublicOutput: (text: string) => sanitizePublicOutput(text),\n      },\n    });\n\n    ctx.log.info(\"memory module ready\");\n  },\n\n  async start() {\n    memoryManager.sessionStore?.startNightlyCompaction();\n\n    // Schedule session archival every 30 minutes if working memory has content\n    setInterval(async () => {\n      const working = memoryManager.getWorkingMemory();\n      if (working.length >= 10) {\n        await memoryManager.archiveSession(true);\n      }\n    }, 30 * 60 * 1000);\n\n    // Run DAG summarization pass every 2 hours\n    setInterval(async () => {\n      try {\n        const result = await runDAGPass(3);\n        if (result.leafSummariesCreated > 0 || result.condensedSummariesCreated > 0) {\n          console.log(`[memory-dag] pass complete — ${result.leafSummariesCreated} leaf, ${result.condensedSummariesCreated} condensed`);\n        }\n      } catch (err) {\n        console.warn(`[memory-dag] pass failed: ${String(err)}`);\n      }\n    }, 2 * 60 * 60 * 1000);\n\n    setInterval(async () => {\n      try {\n        await memoryManager.runMemoryMaintenanceCycle(\"scheduled\");\n      } catch (err) {\n        console.warn(`[memory-canonical] consolidation failed: ${String(err)}`);\n      }\n    }, 6 * 60 * 60 * 1000);\n  },\n\n  async stop() {\n    memoryManager.sessionStore?.stopNightlyCompaction();\n    // Archive on shutdown if there's anything in working memory\n    await memoryManager.archiveSession(false);\n  },\n\n  async healthCheck(): Promise<HealthReport> {\n    const base = process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n    const memoryDir = process.env[\"SQUIDLEY_MEMORY_DIR\"] ?? `${base}/memory`;\n    const dbExists = existsSync(join(memoryDir, \"index.db\"));\n\n    if (!dbExists) {\n      return { status: \"degraded\", trust: \"degraded\", message: \"index.db not found — run init\" };\n    }\n\n    // SQLite ok + embeddings available → trusted\n    if (_embeddingAvailable) {\n      return {\n        status: \"healthy\",\n        trust: \"trusted\",\n        message: `ready — semantic search via ${EMBEDDING_MODEL} (${_searchMode})`,\n        checks: { sqlite: true, embeddings: true },\n      };\n    }\n\n    // SQLite ok + keyword-only → verified\n    return {\n      status: \"healthy\",\n      trust: \"verified\",\n      message: `ready — keyword search only. Run: ollama pull ${EMBEDDING_MODEL} for semantic search`,\n      checks: { sqlite: true, embeddings: false },\n    };\n  },\n};\n",
            "content": "/**\n * Squidley V2 — Memory System\n * ============================================================\n * Five-tier memory architecture. Jarvis-level awareness.\n *\n * Tiers:\n *   working    — current session, in-memory, auto-summarized on end\n *   episodic   — past conversations as markdown + SQLite index\n *   semantic   — extracted facts: machines, projects, decisions, people\n *   project    — per-project namespaces injected when active\n *   preferences — how zen works, what he hates, his style\n *\n * Retrieval:\n *   1. Keyword search (fast, zero-dep)\n *   2. Embedding similarity via Ollama (nomic-embed-text, local, free)\n *   3. Merge, deduplicate, rank by relevance + recency\n *\n * Injection:\n *   - Max 2000 tokens injected per request\n *   - Project context first, then episodic, then semantic facts\n *   - Injected as second system message after persona prompt\n * ============================================================\n */\n\nimport { createRequire } from \"node:module\";\nimport { readFile, writeFile, readdir, mkdir } from \"node:fs/promises\";\nimport { existsSync } from \"node:fs\";\nimport { join, basename } from \"node:path\";\nimport Database from \"better-sqlite3\";\nimport type { SquidleyModule, ModuleContext, HealthReport } from \"@squidley/core/sdk\";\nimport { summarizeSession, formatSummaryAsMarkdown } from \"./summarizer.js\";\nimport { MemoryDAG, migrateToDAG, runDAGPass } from \"./dag.js\";\nimport { SessionStore } from \"./sessions.js\";\nimport { CanonicalMemoryService } from \"./store.js\";\nimport { runMemoryMaintenanceCycle } from \"./maintenance.js\";\n\nconst require = createRequire(import.meta.url);\nimport { sanitizePublicOutput } from \"./sanitize.js\";\nimport type {\n  MemoryCapsuleDocument,\n  MemoryConsolidationReport,\n  MemoryIndexDocument,\n  MemoryUseResolution,\n  MemoryVeritorSnapshot,\n  MemoryWriteInput,\n} from \"./types.js\";\n\n// ── Types ─────────────────────────────────────────────────────────────────────\n\nexport type MemoryTier = \"working\" | \"episodic\" | \"semantic\" | \"project\" | \"preferences\";\n\nexport interface MemoryEntry {\n  id: string;\n  tier: MemoryTier;\n  title: string;\n  content: string;\n  project?: string;\n  tags: string[];\n  createdAt: string;\n  updatedAt: string;\n  /** Embedding vector stored as JSON array */\n  embedding?: number[];\n  /** Relevance score assigned during retrieval */\n  score?: number;\n}\n\nexport interface WorkingMemoryMessage {\n  role: \"user\" | \"assistant\";\n  content: string;\n  timestamp: number;\n  model?: string;\n  tokensIn?: number;\n  tokensOut?: number;\n}\n\nexport interface MemoryContext {\n  entries: MemoryEntry[];\n  totalTokensEstimate: number;\n  injectionBlock: string;\n}\n\nexport interface MemoryWriteOptions {\n  tier: MemoryTier;\n  title: string;\n  content: string;\n  project?: string;\n  tags?: string[];\n}\n\n// ── Constants ─────────────────────────────────────────────────────────────────\n\nconst MAX_INJECT_CHARS   = 8_000;   // ~2000 tokens\nconst EMBEDDING_MODEL    = \"nomic-embed-text\";\nconst SIMILARITY_THRESH  = 0.72;\nconst MAX_RESULTS        = 6;\nconst CHARS_PER_TOKEN    = 4;\n\n// ── Embedding availability tracking ──────────────────────────────────────────\nlet _embeddingAvailable = false;\nlet _embeddingChecked = false;\nlet _searchMode: \"semantic\" | \"keyword\" = \"keyword\";\n\n// ── Keyword extraction ────────────────────────────────────────────────────────\n\nconst STOP_WORDS = new Set([\n  \"the\",\"a\",\"an\",\"and\",\"or\",\"but\",\"in\",\"on\",\"at\",\"to\",\"for\",\"of\",\"with\",\n  \"is\",\"are\",\"was\",\"were\",\"be\",\"been\",\"have\",\"has\",\"had\",\"do\",\"does\",\"did\",\n  \"will\",\"would\",\"could\",\"should\",\"may\",\"might\",\"shall\",\"can\",\"need\",\"must\",\n  \"i\",\"you\",\"he\",\"she\",\"it\",\"we\",\"they\",\"me\",\"him\",\"her\",\"us\",\"them\",\"my\",\n  \"your\",\"his\",\"its\",\"our\",\"their\",\"what\",\"which\",\"who\",\"how\",\"when\",\"where\",\n  \"why\",\"this\",\"that\",\"these\",\"those\",\"so\",\"if\",\"not\",\"no\",\"yes\",\"just\",\"also\",\n]);\n\nfunction extractKeywords(text: string): string[] {\n  return text\n    .toLowerCase()\n    .replace(/[^a-z0-9\\s-]/g, \" \")\n    .split(/\\s+/)\n    .filter(w => w.length > 2 && !STOP_WORDS.has(w))\n    .slice(0, 20);\n}\n\nfunction cosineSimilarity(a: number[], b: number[]): number {\n  if (a.length !== b.length) return 0;\n  let dot = 0, magA = 0, magB = 0;\n  for (let i = 0; i < a.length; i++) {\n    dot  += (a[i] ?? 0) * (b[i] ?? 0);\n    magA += (a[i] ?? 0) ** 2;\n    magB += (b[i] ?? 0) ** 2;\n  }\n  return magA && magB ? dot / (Math.sqrt(magA) * Math.sqrt(magB)) : 0;\n}\n\n// ── Memory Manager ────────────────────────────────────────────────────────────\n\nclass MemoryManager {\n  private memoryDir: string = \"\";\n  private db: InstanceType<typeof Database> | null = null;\n  private ollamaBase: string = \"http://localhost:11434\";\n  private ctx!: ModuleContext;\n  private canonicalMemory: CanonicalMemoryService | null = null;\n\n  /** Working memory — in-RAM, current session only */\n  private workingMemory: WorkingMemoryMessage[] = [];\n  private activeProject: string | null = null;\n  public sessionStore: SessionStore | null = null;\n\n  // ── Initialization ──────────────────────────────────────────────────────────\n\n  async init(ctx: ModuleContext, memoryDir: string, ollamaBase: string): Promise<void> {\n    this.ctx = ctx;\n    this.memoryDir = memoryDir;\n    this.ollamaBase = ollamaBase;\n\n    // Create tier directories\n    for (const tier of [\"working\",\"episodic\",\"semantic\",\"project\",\"preferences\"] as MemoryTier[]) {\n      await mkdir(join(memoryDir, tier), { recursive: true });\n    }\n\n    // Initialize SQLite\n    const dbPath = join(memoryDir, \"index.db\");\n    this.db = new Database(dbPath);\n    this.initDb();\n\n    this.sessionStore = new SessionStore({\n      db: this.db,\n      ctx,\n      memoryDir,\n      ollamaBase,\n      writeMemory: (options) => this.write(options),\n    });\n    this.sessionStore.initSchema();\n\n    const base = process.env[\"SQUIDLEY_BASE_DIR\"] ?? process.cwd();\n    const stateRoot = process.env[\"SQUIDLEY_STATE_DIR\"] ?? join(base, \"state\");\n    this.canonicalMemory = new CanonicalMemoryService(join(stateRoot, \"memory\"), {\n      log: ctx.log,\n      receiptsDir: join(stateRoot, \"receipts\"),\n    });\n    await this.canonicalMemory.init({ repoRoot: base });\n\n    // Seed default semantic entries if fresh install\n    await this.seedDefaults();\n\n    // Run DAG migration (safe to run multiple times — idempotent)\n    try {\n      if (!MemoryDAG.isDAGMigrated()) {\n        migrateToDAG();\n        ctx.log.info(\"memory DAG schema migrated\");\n      }\n    } catch (err) {\n      if (!String(err).includes(\"duplicate column\")) {\n        ctx.log.warn(`DAG migration warning: ${String(err)}`);\n      }\n    }\n\n    // Probe embedding availability (non-blocking — sets _searchMode)\n    await this.probeEmbedding();\n\n    ctx.log.info(`memory system initialized — ${memoryDir} (search=${_searchMode})`);\n  }\n\n  private initDb(): void {\n    const db = this.db!;\n\n    db.exec(`\n      CREATE TABLE IF NOT EXISTS memory_entries (\n        id          TEXT PRIMARY KEY,\n        tier        TEXT NOT NULL,\n        title       TEXT NOT NULL,\n        content     TEXT NOT NULL,\n        project     TEXT,\n        tags        TEXT DEFAULT '[]',\n        created_at  TEXT NOT NULL,\n        updated_at  TEXT NOT NULL,\n        embedding   TEXT,\n        file_path   TEXT\n      );\n\n      CREATE VIRTUAL TABLE IF NOT EXISTS memory_fts\n        USING fts5(id UNINDEXED, title, content, tags, content=memory_entries, content_rowid=rowid);\n\n      CREATE TRIGGER IF NOT EXISTS memory_fts_insert AFTER INSERT ON memory_entries BEGIN\n        INSERT INTO memory_fts(rowid, id, title, content, tags)\n          VALUES (new.rowid, new.id, new.title, new.content, new.tags);\n      END;\n\n      CREATE TRIGGER IF NOT EXISTS memory_fts_update AFTER UPDATE ON memory_entries BEGIN\n        INSERT INTO memory_fts(memory_fts, rowid, id, title, content, tags)\n          VALUES ('delete', old.rowid, old.id, old.title, old.content, old.tags);\n        INSERT INTO memory_fts(rowid, id, title, content, tags)\n          VALUES (new.rowid, new.id, new.title, new.content, new.tags);\n      END;\n\n      CREATE TRIGGER IF NOT EXISTS memory_fts_delete AFTER DELETE ON memory_entries BEGIN\n        INSERT INTO memory_fts(memory_fts, rowid, id, title, content, tags)\n          VALUES ('delete', old.rowid, old.id, old.title, old.content, old.tags);\n      END;\n    `);\n  }\n\n  private async seedDefaults(): Promise<void> {\n    const db = this.db!;\n    const count = (db.prepare(\"SELECT COUNT(*) as n FROM memory_entries WHERE tier='semantic'\").get() as { n: number }).n;\n    if (count > 0) return;\n\n    // Only seed lab-specific data if running on Mushin (full V2).\n    // Squidley Lite gets an empty memory — user builds their own context.\n    const isLite = !process.env[\"OPENROUTER_API_KEY\"] && !process.env[\"ANTHROPIC_API_KEY\"];\n    if (isLite) {\n      this.ctx.log.info(\"Lite mode — skipping lab-specific memory seeds. Memory starts fresh.\");\n      return;\n    }\n\n    // Seed core semantic memory from what we know about the lab\n    const defaults: MemoryWriteOptions[] = [\n      {\n        tier: \"semantic\",\n        title: \"Lab machines\",\n        tags: [\"machines\", \"hardware\", \"infrastructure\"],\n        content: `# Lab Machines\n\n## Mushin (formerly ZenPop)\n- Role: Main development workstation, Squidley V2 host\n- OS: Debian 12 / Mushin OS\n- GPU: NVIDIA RTX 4070\n- CPU: Intel i7-13700K\n- RAM: 32GB\n- Storage: Three NVMe drives — nvme0n1 (OS), nvme1n1 (/mnt/games), nvme2n1 (/mnt/ai)\n- Network: 100.118.60.13 (Tailscale)\n- Squidley V2: /mnt/ai/squidley-v2, port 18791 (API), port 3002 (UI)\n\n## Pop Tart\n- Role: Experimental machine, Krakzen host, red team attacker\n- OS: Debian / Pop!_OS\n- GPU: AMD Radeon RX 6800 (16GB VRAM)\n- CPU: Intel i7 ~10th gen\n- RAM: 32GB DDR5\n- Services: Jellyfin, Krakzen, Zen Council (parked)\n- Network: Tailscale connected\n- Model capacity: Comfortably runs 14B class models`,\n      },\n      {\n        tier: \"semantic\",\n        title: \"Active projects\",\n        tags: [\"projects\", \"architecture\", \"portfolio\"],\n        content: `# Active Projects\n\n## Squidley V2\n- Status: Active build — in development\n- Location: /mnt/ai/squidley-v2\n- Purpose: Local-first AI orchestration platform — the blue team / defender\n- Stack: TypeScript, Next.js, Fastify, pnpm workspaces\n- Key features: streaming chat, 5 providers, prompt injection defense, receipts, memory, diagnostics\n- Design system: Bioluminescent dark theme, Squidley PNG watermark centered\n\n## Krakzen\n- Status: V1 foundation complete on Pop Tart\n- Location: /hogwarts/AI/krakzen\n- Purpose: AI-specific security testing — prompt injection, jailbreaking, LLM manipulation\n- Status: V1 = trainer with guardrails; V2 = full red team (gated on demonstrated knowledge)\n- Built with: GPT (plan to migrate to Claude)\n\n## Archivum\n- Status: Vision captured — sleeper product\n- Purpose: Sovereign personal knowledge base — intake anything, auto-organize, semantic recall\n- Note: This IS the memory system's long-term product form\n\n## Tenticode\n- Status: Designed — build engine\n- Purpose: inspect → plan → patch → review → verify → apply\n- Note: Standalone product, separate repo`,\n      },\n      {\n        tier: \"preferences\",\n        title: \"How zen works\",\n        tags: [\"preferences\", \"workflow\", \"communication\"],\n        content: `# How Zen Works\n\n## Background\n- 20+ years field service technician (copiers, printers, hardware)\n- Former Air Force AGE (Aerospace Ground Equipment) mechanic\n- Self-taught AI systems developer — 9 months\n- Career transition target: Tier 2 tech support → AI Security Engineer\n\n## Working style\n- Full file replacements preferred — never partial patches to apply manually\n- Peer-level engagement — not a student, a builder\n- Honest assessment over encouragement — tell the truth\n- Thinks in systems and projects — connect advice to the bigger picture\n- Obsessive builder — never burned out, fires on all cylinders\n- Military precision — documentation, systematic thinking are natural\n\n## Technical preferences\n- Local-first always\n- Tools over tokens\n- Every action produces a receipt\n- No raw shell access to models\n- Full cost transparency\n\n## Things that matter\n- Job search is completely stealth — never suggest anything that could expose it\n- Money is strategic — never suggest paid tools casually\n- Finds the work genuinely fulfilling — protect that energy\n- Building a portfolio for career transition — every project has resume value`,\n      },\n      {\n        tier: \"semantic\",\n        title: \"Architecture decisions log\",\n        tags: [\"decisions\", \"architecture\", \"v2\"],\n        content: `# Architecture Decisions\n\n## Squidley V2 — Locked Decisions\n- Module discovery: file-based manifest.json in each module dir\n- Event bus: in-process EventEmitter with receipt hooks\n- UI contributions: boot-time static, queryable at runtime\n- Boot model: restart to add/remove modules — no hot-swap (like a receiver)\n- Persona system: pure data — system prompt, tone, name, theme only\n- Core footprint: Pi/phone deployable\n- Repos: four separate repos (Squidley, Krakzen, Archivum, Tenticode)\n- Design system: bioluminescent dark — locked v4, DO NOT redesign\n\n## Key Principles\n- Receiver analogy: turn off before adding modules\n- Chimp painting aesthetic: dark neutral base, precise color pops\n- Squidley meditates behind the UI — front and center\n- Memory is one of her most important features — must be Jarvis-level`,\n      },\n    ];\n\n    for (const entry of defaults) {\n      await this.write(entry);\n    }\n  }\n\n  // ── Write ───────────────────────────────────────────────────────────────────\n\n  async write(options: MemoryWriteOptions): Promise<string> {\n    const id = `${options.tier}-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;\n    const now = new Date().toISOString();\n    const tags = options.tags ?? [];\n    const filename = `${options.title.toLowerCase().replace(/[^a-z0-9]+/g,\"-\").slice(0,50)}.md`;\n    const tierDir = join(this.memoryDir, options.tier, ...(options.project ? [options.project] : []));\n    await mkdir(tierDir, { recursive: true });\n    const filePath = join(tierDir, filename);\n\n    // Write markdown file\n    const mdContent = [\n      `# ${options.title}`,\n      `_tier: ${options.tier} | tags: ${tags.join(\", \")} | updated: ${now}_`,\n      \"\",\n      options.content,\n    ].join(\"\\n\");\n    await writeFile(filePath, mdContent, \"utf-8\");\n\n    // Try to get embedding (non-blocking — fails gracefully if Ollama not running)\n    let embedding: number[] | undefined;\n    try {\n      embedding = await this.embed(options.content.slice(0, 2000));\n    } catch { /* ollama not available — skip */ }\n\n    // Upsert in SQLite\n    const db = this.db!;\n    const existing = db.prepare(\"SELECT id FROM memory_entries WHERE file_path = ?\").get(filePath) as { id: string } | undefined;\n\n    if (existing) {\n      db.prepare(`\n        UPDATE memory_entries SET title=?, content=?, tags=?, updated_at=?, embedding=?, project=?\n        WHERE file_path=?\n      `).run(options.title, options.content, JSON.stringify(tags), now,\n             embedding ? JSON.stringify(embedding) : null,\n             options.project ?? null, filePath);\n      return existing.id;\n    } else {\n      db.prepare(`\n        INSERT INTO memory_entries (id, tier, title, content, project, tags, created_at, updated_at, embedding, file_path)\n        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)\n      `).run(id, options.tier, options.title, options.content,\n             options.project ?? null, JSON.stringify(tags),\n             now, now,\n             embedding ? JSON.stringify(embedding) : null,\n             filePath);\n      return id;\n    }\n  }\n\n  // ── Retrieve ────────────────────────────────────────────────────────────────\n\n  async retrieve(query: string, project?: string): Promise<MemoryContext> {\n    const keywords = extractKeywords(query);\n    const results = new Map<string, MemoryEntry & { score: number }>();\n\n    // Layer 1: FTS keyword search\n    if (keywords.length > 0) {\n      // Use prefix matching (k*) for short terms, exact for longer ones\n      const ftsQuery = keywords.map(k => k.length <= 4 ? `${k}*` : `\"${k}\"`).join(\" OR \");\n      try {\n        const rows = this.db!.prepare(`\n          SELECT e.*, rank as fts_rank\n          FROM memory_entries e\n          JOIN memory_fts f ON e.id = f.id\n          WHERE memory_fts MATCH ?\n          ${project ? \"AND (e.project = ? OR e.project IS NULL)\" : \"\"}\n          ORDER BY rank\n          LIMIT 20\n        `).all(ftsQuery, ...(project ? [project] : [])) as Array<Record<string, unknown>>;\n\n        for (const row of rows) {\n          const entry = rowToEntry(row);\n          results.set(entry.id, { ...entry, score: 1.0 - (Number(row[\"fts_rank\"] ?? 0) / 10) });\n        }\n      } catch { /* fts error — continue */ }\n    }\n\n    // Layer 2: Embedding similarity for gaps\n    let queryEmbedding: number[] | undefined;\n    try {\n      queryEmbedding = await this.embed(query.slice(0, 500));\n    } catch { /* ollama not running */ }\n\n    if (queryEmbedding) {\n      const allRows = this.db!.prepare(`\n        SELECT * FROM memory_entries WHERE embedding IS NOT NULL\n        ${project ? \"AND (project = ? OR project IS NULL)\" : \"\"}\n      `).all(...(project ? [project] : [])) as Array<Record<string, unknown>>;\n\n      for (const row of allRows) {\n        if (results.has(row[\"id\"] as string)) continue; // already found by FTS\n        try {\n          const emb = JSON.parse(row[\"embedding\"] as string) as number[];\n          const sim = cosineSimilarity(queryEmbedding, emb);\n          if (sim >= SIMILARITY_THRESH) {\n            const entry = rowToEntry(row);\n            results.set(entry.id, { ...entry, score: sim });\n          }\n        } catch { /* skip malformed embedding */ }\n      }\n    }\n\n    // Layer 3: Always include active project memory + preferences AND the\n    // ambient `current_activity` slot written by the screen-watcher module\n    // (when enabled). The slot is upserted-by-title so there's at most one\n    // row at any given moment.\n    const alwaysInclude = this.db!.prepare(`\n      SELECT * FROM memory_entries\n      WHERE tier IN ('preferences')\n         OR (tier = 'working' AND title = 'current_activity')\n      ${project ? \"OR (tier = 'project' AND project = ?)\" : \"\"}\n      LIMIT 4\n    `).all(...(project ? [project] : [])) as Array<Record<string, unknown>>;\n\n    for (const row of alwaysInclude) {\n      if (!results.has(row[\"id\"] as string)) {\n        results.set(row[\"id\"] as string, { ...rowToEntry(row), score: 0.5 });\n      }\n    }\n\n    // Rank, deduplicate, trim to budget\n    const ranked = [...results.values()]\n      .sort((a, b) => b.score - a.score)\n      .slice(0, MAX_RESULTS);\n\n    let canonicalBlock = \"\";\n    if (this.canonicalMemory) {\n      try {\n        const canonical = await this.canonicalMemory.retrieveHints(query);\n        canonicalBlock = canonical.injectionBlock.trim();\n      } catch (err) {\n        this.ctx.log.warn(`canonical memory hint retrieval failed: ${String(err)}`);\n      }\n    }\n\n    // Build injection block\n    const injectionParts: string[] = [\n      ...(canonicalBlock ? [canonicalBlock, \"\"] : []),\n      \"# Squidley Memory Context\",\n      `_Retrieved ${ranked.length} relevant long-form memories_`,\n      \"\",\n    ];\n\n    let charCount = injectionParts.join(\"\\n\").length;\n\n    for (const entry of ranked) {\n      const section = [`## ${entry.title}`, `_${entry.tier}${entry.project ? ` · ${entry.project}` : \"\"}_`, \"\", entry.content, \"\"].join(\"\\n\");\n      if (charCount + section.length > MAX_INJECT_CHARS) break;\n      injectionParts.push(section);\n      charCount += section.length;\n    }\n\n    const injectionBlock = injectionParts.join(\"\\n\");\n\n    return {\n      entries: ranked,\n      totalTokensEstimate: Math.ceil(charCount / CHARS_PER_TOKEN),\n      injectionBlock,\n    };\n  }\n\n  /**\n   * Look up a single memory entry by id. Returns null if not found or if the\n   * db is uninitialized. Used by the chat-callable `memory.get` tool.\n   */\n  getEntryById(id: string): MemoryEntry | null {\n    if (!this.db) return null;\n    try {\n      const row = this.db\n        .prepare(\"SELECT * FROM memory_entries WHERE id = ? LIMIT 1\")\n        .get(id) as Record<string, unknown> | undefined;\n      if (!row) return null;\n      return rowToEntry(row);\n    } catch {\n      return null;\n    }\n  }\n\n  /**\n   * Run the retrieval pipeline and return just the ranked entries, optionally\n   * filtered by tier and capped at `topK`. Used by the chat-callable\n   * `memory.search` tool — thin wrapper so we don't duplicate the retrieval\n   * logic, but we strip the MemoryContext injection-block wrapping.\n   */\n  async searchEntries(opts: {\n    query: string;\n    project?: string | undefined;\n    tier?: MemoryTier | undefined;\n    topK?: number | undefined;\n  }): Promise<MemoryEntry[]> {\n    const ctx = await this.retrieve(opts.query, opts.project);\n    let entries = ctx.entries;\n    if (opts.tier) entries = entries.filter((e) => e.tier === opts.tier);\n    const k = Math.max(1, Math.min(opts.topK ?? 5, MAX_RESULTS));\n    return entries.slice(0, k);\n  }\n\n  // ── Working memory ──────────────────────────────────────────────────────────\n\n  addToWorking(msg: WorkingMemoryMessage): void {\n    this.workingMemory.push(msg);\n    // Keep last 100 messages in working memory\n    if (this.workingMemory.length > 100) {\n      this.workingMemory = this.workingMemory.slice(-100);\n    }\n  }\n\n  getWorkingMemory(): WorkingMemoryMessage[] {\n    return [...this.workingMemory];\n  }\n\n  setActiveProject(project: string | null): void {\n    this.activeProject = project;\n  }\n\n  getActiveProject(): string | null {\n    return this.activeProject;\n  }\n\n  /**\n   * Archive working memory to episodic.\n   * Summarizes the conversation and extracts key facts.\n   * Called at end of session or when context window is getting full.\n   */\n  async archiveSession(summarize: boolean = true): Promise<void> {\n    if (this.workingMemory.length < 2) return;\n\n    const sessionDate = new Date().toISOString().split(\"T\")[0] ?? new Date().toDateString();\n    const msgCount = this.workingMemory.length;\n    const messagesSnapshot = [...this.workingMemory];\n\n    let content: string;\n    let tags = [\"session\", \"auto-archived\", sessionDate];\n\n    if (summarize) {\n      this.ctx.log.info(`summarizing session — ${msgCount} messages via local model`);\n      try {\n        const summary = await summarizeSession(messagesSnapshot);\n        content = formatSummaryAsMarkdown(summary);\n        tags = [...tags, ...summary.entities.projects.slice(0, 3)];\n\n        // Promote new facts to semantic memory\n        for (const fact of summary.newFacts.slice(0, 5)) {\n          await this.write({\n            tier: \"semantic\",\n            title: `Fact — ${sessionDate}`,\n            content: fact,\n            ...(this.activeProject ? { project: this.activeProject } : {}),\n            tags: [\"auto-extracted\", sessionDate],\n          });\n        }\n        this.ctx.log.info(`session summarized — decisions: ${summary.decisions.length}, facts: ${summary.newFacts.length}, actions: ${summary.actionItems.length}`);\n      } catch (err) {\n        // Summarization failed — fall back to raw transcript\n        this.ctx.log.warn(`summarization failed, saving raw: ${String(err)}`);\n        const transcript = messagesSnapshot\n          .map(m => `**${m.role === \"user\" ? \"zen\" : \"squidley\"}**: ${m.content}`)\n          .join(\"\\n\\n\");\n        content = [`## Session ${sessionDate} — ${msgCount} messages`, \"\", transcript].join(\"\\n\");\n      }\n    } else {\n      const transcript = messagesSnapshot\n        .map(m => `**${m.role === \"user\" ? \"zen\" : \"squidley\"}**: ${m.content}`)\n        .join(\"\\n\\n\");\n      content = [`## Session ${sessionDate} — ${msgCount} messages (raw)`, \"\", transcript].join(\"\\n\");\n    }\n\n    await this.write({\n      tier: \"episodic\",\n      title: `Session ${sessionDate}`,\n      content,\n      ...(this.activeProject ? { project: this.activeProject } : {}),\n      tags,\n    });\n\n    this.ctx.log.info(`session archived — ${msgCount} messages → episodic memory`);\n    this.workingMemory = [];\n  }\n\n  // ── Embedding via Ollama ────────────────────────────────────────────────────\n\n  private async embed(text: string): Promise<number[]> {\n    const res = await fetch(`${this.ollamaBase}/api/embeddings`, {\n      method: \"POST\",\n      headers: { \"Content-Type\": \"application/json\" },\n      body: JSON.stringify({ model: EMBEDDING_MODEL, prompt: text }),\n      signal: AbortSignal.timeout(5000),\n    });\n    if (!res.ok) throw new Error(`Ollama embedding ${res.status}`);\n    const data = await res.json() as { embedding: number[] };\n    if (!_embeddingAvailable) {\n      _embeddingAvailable = true;\n      _searchMode = \"semantic\";\n      this.ctx.log.info(`semantic search enabled — ${EMBEDDING_MODEL} via Ollama`);\n    }\n    return data.embedding;\n  }\n\n  /** Probe embedding availability at startup — sets mode without blocking */\n  private async probeEmbedding(): Promise<void> {\n    if (_embeddingChecked) return;\n    _embeddingChecked = true;\n    try {\n      await this.embed(\"test\");\n      // _embeddingAvailable set inside embed() on success\n    } catch {\n      _embeddingAvailable = false;\n      _searchMode = \"keyword\";\n      this.ctx.log.info(\"Vector search unavailable — using keyword search (install ollama nomic-embed-text for better results)\");\n    }\n  }\n\n  /** Get health info for /memoria/health endpoint */\n  getHealthInfo(): {\n    ok: boolean;\n    mode: \"keyword\" | \"semantic\";\n    embeddingModel: string | null;\n    entryCount: number;\n    dbSizeBytes: number;\n    setupHints: string[];\n  } {\n    let entryCount = 0;\n    let dbSizeBytes = 0;\n    try {\n      const row = this.db!.prepare(\"SELECT COUNT(*) as n FROM memory_entries\").get() as { n: number };\n      entryCount = row.n;\n    } catch { /* db may not be ready */ }\n\n    try {\n      const { statSync } = require(\"node:fs\") as typeof import(\"node:fs\");\n      const dbPath = join(this.memoryDir, \"index.db\");\n      dbSizeBytes = statSync(dbPath).size;\n    } catch { /* file not found */ }\n\n    const hints: string[] = [];\n    if (!_embeddingAvailable) {\n      hints.push(\"ollama pull nomic-embed-text for semantic search\");\n    }\n\n    return {\n      ok: !!this.db,\n      mode: _searchMode,\n      embeddingModel: _embeddingAvailable ? EMBEDDING_MODEL : null,\n      entryCount,\n      dbSizeBytes,\n      setupHints: hints,\n    };\n  }\n\n  async getCanonicalIndex(): Promise<MemoryIndexDocument> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.getIndex();\n  }\n\n  async getMemoryCapsule(topic: string): Promise<MemoryCapsuleDocument | null> {\n    if (!this.canonicalMemory) throw new Error(\"Canonical memory not initialized\");\n    return this.canonicalMemory.getCapsule(topic);\n  }\n\n  async remember(input: MemoryWriteInput) {\n    if (!this.canonicalMemory) throw new Error(\"Canonical